//+------------------------------------------------------------------+
//|                        US30_Analyzer.mq5                        |
//|              Analizador Cuantitativo Avanzado - US30 M5         |
//|                                                                  |
//|  Incluye:                                                        |
//|   - EMA 9, 21, 50, 200                                          |
//|   - RSI (14)                                                     |
//|   - MACD (12,26,9)                                              |
//|   - Volume Delta (presión compradora/vendedora)                  |
//|   - Fair Value Gaps (FVG) alcistas y bajistas                   |
//|   - Patrones de velas (Engulfing, Doji, Hammer, Pin Bar, etc.)  |
//|   - Estructura de mercado SMC (BOS, CHoCH, Liq. Sweep)         |
//|   - Soporte / Resistencia automáticos (Pivot Points)            |
//|   - Score de señal consolidado -10 a +10                        |
//|   - Gestión de riesgo con ATR (SL/TP dinámicos)                |
//|   - Exportación automática a CSV                                 |
//+------------------------------------------------------------------+

#property copyright "US30 Quantitative Analyzer v1.0"
#property version   "1.00"
#property strict

//--- Inputs configurables
input string   InpSymbol        = "US30.cash";  // Símbolo (ajusta a tu broker)
input int      InpBars          = 500;           // Velas a analizar
input int      InpEMAFast       = 9;             // EMA rápida
input int      InpEMAMid        = 21;            // EMA media
input int      InpEMASlow       = 50;            // EMA lenta
input int      InpEMATrend      = 200;           // EMA tendencia
input int      InpRSIPeriod     = 14;            // Periodo RSI
input double   InpRSIOverbought = 70.0;          // RSI sobrecompra
input double   InpRSIOversold   = 30.0;          // RSI sobreventa
input int      InpMACDFast      = 12;            // MACD rápido
input int      InpMACDSlow      = 26;            // MACD lento
input int      InpMACDSignal    = 9;             // MACD señal
input int      InpATRPeriod     = 14;            // Periodo ATR
input double   InpATRSLMult     = 1.5;           // ATR multiplicador SL
input double   InpATRTPMult     = 3.0;           // ATR multiplicador TP
input int      InpSRLookback    = 20;            // Lookback S/R pivots
input int      InpFVGLookback   = 50;            // Lookback FVG
input double   InpRiskPct       = 1.0;           // % riesgo por operación
input string   InpCSVFileName   = "US30_Analysis_Report"; // Nombre CSV (sin .csv)
input bool     InpAutoRun       = true;          // Ejecutar al cargar

//--- Handles de indicadores
int hEMAFast, hEMAMid, hEMASlow, hEMATrend;
int hRSI, hMACD, hATR;

//--- Buffers globales
double emaFast[], emaMid[], emaSlow[], emaTrend[];
double rsi[], macdMain[], macdSignal[], macdHist[];
double atrBuf[];

//+------------------------------------------------------------------+
//| Expert initialization                                            |
//+------------------------------------------------------------------+
int OnInit()
{
   //--- Crear handles
   hEMAFast  = iMA(InpSymbol, PERIOD_M5, InpEMAFast,  0, MODE_EMA, PRICE_CLOSE);
   hEMAMid   = iMA(InpSymbol, PERIOD_M5, InpEMAMid,   0, MODE_EMA, PRICE_CLOSE);
   hEMASlow  = iMA(InpSymbol, PERIOD_M5, InpEMASlow,  0, MODE_EMA, PRICE_CLOSE);
   hEMATrend = iMA(InpSymbol, PERIOD_M5, InpEMATrend, 0, MODE_EMA, PRICE_CLOSE);
   hRSI      = iRSI(InpSymbol, PERIOD_M5, InpRSIPeriod, PRICE_CLOSE);
   hMACD     = iMACD(InpSymbol, PERIOD_M5, InpMACDFast, InpMACDSlow, InpMACDSignal, PRICE_CLOSE);
   hATR      = iATR(InpSymbol, PERIOD_M5, InpATRPeriod);

   if(hEMAFast==INVALID_HANDLE || hEMAMid==INVALID_HANDLE ||
      hEMASlow==INVALID_HANDLE || hEMATrend==INVALID_HANDLE ||
      hRSI==INVALID_HANDLE     || hMACD==INVALID_HANDLE     ||
      hATR==INVALID_HANDLE)
   {
      Print("❌ Error creando handles de indicadores: ", GetLastError());
      return INIT_FAILED;
   }

   ArraySetAsSeries(emaFast,   true);
   ArraySetAsSeries(emaMid,    true);
   ArraySetAsSeries(emaSlow,   true);
   ArraySetAsSeries(emaTrend,  true);
   ArraySetAsSeries(rsi,       true);
   ArraySetAsSeries(macdMain,  true);
   ArraySetAsSeries(macdSignal,true);
   ArraySetAsSeries(macdHist,  true);
   ArraySetAsSeries(atrBuf,    true);

   Print("✅ US30 Analyzer inicializado correctamente.");

   if(InpAutoRun)
      EventSetTimer(2); // Ejecuta análisis 2 segundos después de cargar

   return INIT_SUCCEEDED;
}

//+------------------------------------------------------------------+
//| Timer event - ejecuta el análisis al iniciar                    |
//+------------------------------------------------------------------+
void OnTimer()
{
   EventKillTimer();
   RunFullAnalysis();
}

//+------------------------------------------------------------------+
//| Deinit                                                           |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
{
   IndicatorRelease(hEMAFast);
   IndicatorRelease(hEMAMid);
   IndicatorRelease(hEMASlow);
   IndicatorRelease(hEMATrend);
   IndicatorRelease(hRSI);
   IndicatorRelease(hMACD);
   IndicatorRelease(hATR);
}

//+------------------------------------------------------------------+
//| OnChartEvent - botón manual en chart                            |
//+------------------------------------------------------------------+
void OnChartEvent(const int id, const long& lparam,
                  const double& dparam, const string& sparam)
{
   if(id == CHARTEVENT_KEYDOWN && lparam == 65) // Tecla 'A'
      RunFullAnalysis();
}

//+------------------------------------------------------------------+
//| FUNCIÓN PRINCIPAL DE ANÁLISIS                                    |
//+------------------------------------------------------------------+
void RunFullAnalysis()
{
   Print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   Print("  🔄 Iniciando análisis completo US30 M5...");
   Print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

   //--- Copiar datos OHLCV
   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   int copied = CopyRates(InpSymbol, PERIOD_M5, 0, InpBars, rates);
   if(copied <= 0)
   {
      Print("❌ No se pudieron obtener datos para ", InpSymbol);
      return;
   }

   //--- Copiar buffers de indicadores
   int needed = MathMin(copied, 300);
   CopyBuffer(hEMAFast,   0, 0, needed, emaFast);
   CopyBuffer(hEMAMid,    0, 0, needed, emaMid);
   CopyBuffer(hEMASlow,   0, 0, needed, emaSlow);
   CopyBuffer(hEMATrend,  0, 0, needed, emaTrend);
   CopyBuffer(hRSI,       0, 0, needed, rsi);
   CopyBuffer(hMACD,      0, 0, needed, macdMain);
   CopyBuffer(hMACD,      1, 0, needed, macdSignal);
   CopyBuffer(hATR,       0, 0, needed, atrBuf);

   // Histograma MACD manual
   ArrayResize(macdHist, needed);
   for(int i = 0; i < needed; i++)
      macdHist[i] = macdMain[i] - macdSignal[i];

   double price = rates[0].close;
   double atr   = atrBuf[0];

   //=================================================================
   // 1. VOLUMEN DELTA
   //=================================================================
   double buyVol = 0, sellVol = 0, totalVol = 0;
   for(int i = 0; i < 20; i++)
   {
      double vol = (double)rates[i].tick_volume;
      if(rates[i].close >= rates[i].open) buyVol  += vol;
      else                                 sellVol += vol;
      totalVol += vol;
   }
   double deltaPct = (totalVol > 0) ? ((buyVol - sellVol) / totalVol * 100.0) : 0.0;
   double delta    = buyVol - sellVol;

   //=================================================================
   // 2. SOPORTE / RESISTENCIA (Pivot Points)
   //=================================================================
   double supports[5], resistances[5];
   int    supCount = 0, resCount = 0;
   FindSRLevels(rates, copied, price, supports, supCount, resistances, resCount);

   //=================================================================
   // 3. FAIR VALUE GAPS
   //=================================================================
   string fvgTypes[10];
   double fvgTop[10], fvgBottom[10], fvgMid[10];
   int    fvgCount = 0;
   FindFVG(rates, fvgTypes, fvgTop, fvgBottom, fvgMid, fvgCount);

   //=================================================================
   // 4. PATRONES DE VELAS
   //=================================================================
   string candleNames[10];
   string candleDir[10];
   int    candleCount = 0;
   DetectCandlePatterns(rates, candleNames, candleDir, candleCount);

   //=================================================================
   // 5. ESTRUCTURA DE MERCADO (SMC)
   //=================================================================
   string smc_names[10];
   string smc_dir[10];
   string smc_desc[10];
   int    smcCount = 0;
   DetectMarketStructure(rates, needed, smc_names, smc_dir, smc_desc, smcCount);

   //=================================================================
   // 6. SCORE Y SEÑAL CONSOLIDADA
   //=================================================================
   double score = 0.0;
   string scoreDetail = "";
   CalculateScore(rates, price, atr, emaFast[0], emaMid[0], emaSlow[0], emaTrend[0],
                  rsi[0], macdMain[0], macdSignal[0], macdHist[0],
                  deltaPct, candleNames, candleDir, candleCount,
                  smc_names, smc_dir, smcCount,
                  fvgMid, fvgTypes, fvgCount,
                  supports, supCount, resistances, resCount,
                  score, scoreDetail);

   string signal     = (score >=  4.0) ? "COMPRA"  :
                       (score <= -4.0) ? "VENTA"   : "ESPERAR";
   int    confidence = 0;
   if(signal == "COMPRA")       confidence = (int)MathMin((score  / 10.0) * 100.0, 95.0);
   else if(signal == "VENTA")   confidence = (int)MathMin((-score / 10.0) * 100.0, 95.0);
   else                         confidence = (int)(50.0 - MathAbs(score) * 6.25);

   //=================================================================
   // 7. GESTIÓN DE RIESGO
   //=================================================================
   double slPts = atr * InpATRSLMult;
   double tpPts = atr * InpATRTPMult;
   double rr    = (slPts > 0) ? tpPts / slPts : 0;
   double slPrice = 0, tpPrice = 0;
   if(signal == "COMPRA")      { slPrice = price - slPts; tpPrice = price + tpPts; }
   else if(signal == "VENTA")  { slPrice = price + slPts; tpPrice = price - tpPts; }
   double balance     = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount  = balance * (InpRiskPct / 100.0);

   //=================================================================
   // 8. IMPRIMIR EN JOURNAL
   //=================================================================
   PrintAnalysisReport(price, atr, emaFast[0], emaMid[0], emaSlow[0], emaTrend[0],
                       rsi[0], macdMain[0], macdSignal[0], macdHist[0],
                       deltaPct, delta, buyVol, sellVol,
                       signal, score, confidence,
                       slPrice, tpPrice, slPts, tpPts, rr, riskAmount, balance,
                       supports, supCount, resistances, resCount,
                       fvgTypes, fvgTop, fvgBottom, fvgMid, fvgCount,
                       candleNames, candleDir, candleCount,
                       smc_names, smc_dir, smc_desc, smcCount,
                       scoreDetail);

   //=================================================================
   // 9. EXPORTAR CSV
   //=================================================================
   ExportCSV(rates, needed,
             price, atr, emaFast, emaMid, emaSlow, emaTrend, rsi, macdMain, macdSignal, macdHist,
             signal, score, confidence,
             slPrice, tpPrice, slPts, tpPts, rr, riskAmount, balance,
             supports, supCount, resistances, resCount,
             fvgTypes, fvgTop, fvgBottom, fvgMid, fvgCount,
             candleNames, candleDir, candleCount,
             smc_names, smc_dir, smc_desc, smcCount,
             buyVol, sellVol, deltaPct);

   Print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
   Print("  ✅ Análisis completado. CSV exportado en MQL5/Files/");
   Print("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
}

//+------------------------------------------------------------------+
//| SOPORTE / RESISTENCIA - Pivot Highs & Lows                      |
//+------------------------------------------------------------------+
void FindSRLevels(const MqlRates &rates[], int total,
                  double price,
                  double &supports[], int &supCount,
                  double &resistances[], int &resCount)
{
   supCount = 0; resCount = 0;
   int lb = InpSRLookback;

   for(int i = lb; i < total - lb && (supCount < 5 || resCount < 5); i++)
   {
      // Pivot High
      bool isHigh = true;
      for(int j = i - lb; j <= i + lb; j++)
         if(j != i && rates[j].high >= rates[i].high) { isHigh = false; break; }
      if(isHigh && rates[i].high > price && resCount < 5)
         resistances[resCount++] = rates[i].high;

      // Pivot Low
      bool isLow = true;
      for(int j = i - lb; j <= i + lb; j++)
         if(j != i && rates[j].low <= rates[i].low) { isLow = false; break; }
      if(isLow && rates[i].low < price && supCount < 5)
         supports[supCount++] = rates[i].low;
   }

   // Ordenar: soportes descendente, resistencias ascendente
   for(int a = 0; a < supCount-1; a++)
      for(int b = a+1; b < supCount; b++)
         if(supports[b] > supports[a]) { double t=supports[a]; supports[a]=supports[b]; supports[b]=t; }

   for(int a = 0; a < resCount-1; a++)
      for(int b = a+1; b < resCount; b++)
         if(resistances[b] < resistances[a]) { double t=resistances[a]; resistances[a]=resistances[b]; resistances[b]=t; }
}

//+------------------------------------------------------------------+
//| FAIR VALUE GAPS                                                  |
//+------------------------------------------------------------------+
void FindFVG(const MqlRates &rates[],
             string &types[], double &tops[], double &bottoms[], double &mids[],
             int &count)
{
   count = 0;
   int lookback = MathMin(InpFVGLookback, ArraySize(rates) - 1);

   for(int i = 2; i < lookback && count < 10; i++)
   {
      // Bullish FVG: low[i] > high[i-2]
      if(rates[i].low > rates[i-2].high)
      {
         types[count]   = "Bullish";
         tops[count]    = rates[i].low;
         bottoms[count] = rates[i-2].high;
         mids[count]    = (tops[count] + bottoms[count]) / 2.0;
         count++;
      }
      // Bearish FVG: high[i] < low[i-2]
      else if(rates[i].high < rates[i-2].low)
      {
         types[count]   = "Bearish";
         tops[count]    = rates[i-2].low;
         bottoms[count] = rates[i].high;
         mids[count]    = (tops[count] + bottoms[count]) / 2.0;
         count++;
      }
   }
}

//+------------------------------------------------------------------+
//| PATRONES DE VELAS                                                |
//+------------------------------------------------------------------+
void DetectCandlePatterns(const MqlRates &rates[],
                          string &names[], string &dirs[], int &count)
{
   count = 0;
   if(ArraySize(rates) < 4) return;

   MqlRates c  = rates[0]; // vela actual
   MqlRates p  = rates[1]; // anterior
   MqlRates pp = rates[2]; // dos atrás

   double body       = MathAbs(c.close - c.open);
   double fullRange  = c.high - c.low;
   if(fullRange == 0) return;

   double upperWick  = c.high - MathMax(c.close, c.open);
   double lowerWick  = MathMin(c.close, c.open) - c.low;
   double bodyRatio  = body / fullRange;
   double upperRatio = upperWick / fullRange;
   double lowerRatio = lowerWick / fullRange;

   // Doji
   if(bodyRatio < 0.10)
   { names[count]="Doji"; dirs[count]="NEUTRAL"; count++; }

   // Hammer alcista
   if(lowerRatio > 0.60 && upperRatio < 0.10 && c.close > c.open)
   { names[count]="Hammer"; dirs[count]="BULLISH"; count++; }

   // Shooting Star bajista
   if(upperRatio > 0.60 && lowerRatio < 0.10 && c.close < c.open)
   { names[count]="Shooting Star"; dirs[count]="BEARISH"; count++; }

   // Pin Bar alcista
   if(lowerRatio > 0.65 && bodyRatio < 0.25)
   { names[count]="Pin Bar Alcista"; dirs[count]="BULLISH"; count++; }

   // Pin Bar bajista
   if(upperRatio > 0.65 && bodyRatio < 0.25)
   { names[count]="Pin Bar Bajista"; dirs[count]="BEARISH"; count++; }

   // Bullish Engulfing
   if(c.close > c.open && p.close < p.open &&
      c.open < p.close && c.close > p.open)
   { names[count]="Bullish Engulfing"; dirs[count]="BULLISH"; count++; }

   // Bearish Engulfing
   if(c.close < c.open && p.close > p.open &&
      c.open > p.close && c.close < p.open)
   { names[count]="Bearish Engulfing"; dirs[count]="BEARISH"; count++; }

   // Morning Star
   double ppBody = MathAbs(pp.close - pp.open);
   double pBody  = MathAbs(p.close  - p.open);
   if(pp.close < pp.open &&
      pBody < ppBody * 0.3 &&
      c.close > c.open &&
      c.close > (pp.open + pp.close) / 2.0)
   { names[count]="Morning Star"; dirs[count]="BULLISH"; count++; }

   // Evening Star
   if(pp.close > pp.open &&
      pBody < ppBody * 0.3 &&
      c.close < c.open &&
      c.close < (pp.open + pp.close) / 2.0)
   { names[count]="Evening Star"; dirs[count]="BEARISH"; count++; }

   // Marubozu alcista
   if(c.close > c.open && upperRatio < 0.05 && lowerRatio < 0.05 && bodyRatio > 0.90)
   { names[count]="Marubozu Alcista"; dirs[count]="BULLISH"; count++; }

   // Marubozu bajista
   if(c.close < c.open && upperRatio < 0.05 && lowerRatio < 0.05 && bodyRatio > 0.90)
   { names[count]="Marubozu Bajista"; dirs[count]="BEARISH"; count++; }
}

//+------------------------------------------------------------------+
//| ESTRUCTURA DE MERCADO - SMC                                      |
//+------------------------------------------------------------------+
void DetectMarketStructure(const MqlRates &rates[], int total,
                           string &names[], string &dirs[], string &descs[],
                           int &count)
{
   count = 0;
   if(total < 15) return;

   double prevHigh = 0, prevLow = DBL_MAX;
   for(int i = 3; i < 15; i++)
   {
      if(rates[i].high > prevHigh) prevHigh = rates[i].high;
      if(rates[i].low  < prevLow)  prevLow  = rates[i].low;
   }

   // BOS Alcista
   if(rates[0].close > prevHigh && rates[1].close <= prevHigh)
   {
      names[count]="BOS Alcista"; dirs[count]="BULLISH";
      descs[count]=StringFormat("Rompe %.0f", prevHigh);
      count++;
   }
   // BOS Bajista
   if(rates[0].close < prevLow && rates[1].close >= prevLow)
   {
      names[count]="BOS Bajista"; dirs[count]="BEARISH";
      descs[count]=StringFormat("Rompe %.0f", prevLow);
      count++;
   }

   // CHoCH - Cambio de carácter
   double h5[5], l5[5];
   for(int i = 0; i < 5; i++) { h5[i]=rates[i].high; l5[i]=rates[i].low; }
   if(h5[0] < h5[2] && l5[0] < l5[2])
   { names[count]="CHoCH Bajista"; dirs[count]="BEARISH"; descs[count]="Cambio de caracter"; count++; }
   else if(h5[0] > h5[2] && l5[0] > l5[2])
   { names[count]="CHoCH Alcista"; dirs[count]="BULLISH"; descs[count]="Cambio de caracter"; count++; }

   // Liquidity Sweep
   double swingLow = DBL_MAX, swingHigh = 0;
   for(int i = 2; i < 12; i++)
   {
      if(rates[i].low  < swingLow)  swingLow  = rates[i].low;
      if(rates[i].high > swingHigh) swingHigh = rates[i].high;
   }
   if(rates[0].low < swingLow && rates[0].close > swingLow)
   {
      names[count]="Liq. Sweep LOW"; dirs[count]="BULLISH";
      descs[count]=StringFormat("Barrida bajo %.0f", swingLow);
      count++;
   }
   if(rates[0].high > swingHigh && rates[0].close < swingHigh)
   {
      names[count]="Liq. Sweep HIGH"; dirs[count]="BEARISH";
      descs[count]=StringFormat("Barrida sobre %.0f", swingHigh);
      count++;
   }
}

//+------------------------------------------------------------------+
//| CÁLCULO DEL SCORE CONSOLIDADO                                   |
//+------------------------------------------------------------------+
void CalculateScore(const MqlRates &rates[], double price, double atr,
                    double ef, double em, double es, double et,
                    double rsiVal, double macdVal, double macdSig, double macdHistVal,
                    double deltaPct,
                    string &cNames[], string &cDirs[], int cCount,
                    string &smcNames[], string &smcDirs[], int smcCount,
                    double &fvgMid[], string &fvgType[], int fvgCount,
                    double &supports[], int supCount,
                    double &resistances[], int resCount,
                    double &score, string &detail)
{
   score  = 0.0;
   detail = "";

   // EMA Tendencia
   if(price > et) { score += 1.5; detail += "[+1.5] Precio sobre EMA200|"; }
   else           { score -= 1.5; detail += "[-1.5] Precio bajo EMA200|"; }

   // Alineación EMAs alcista
   if(ef > em && em > es && es > et)
   { score += 2.0; detail += "[+2.0] EMAs alineadas ALCISTA|"; }
   else if(ef < em && em < es && es < et)
   { score -= 2.0; detail += "[-2.0] EMAs alineadas BAJISTA|"; }

   // RSI
   if(rsiVal < InpRSIOversold)       { score += 1.5; detail += StringFormat("[+1.5] RSI sobrevendido (%.1f)|", rsiVal); }
   else if(rsiVal > InpRSIOverbought){ score -= 1.5; detail += StringFormat("[-1.5] RSI sobrecomprado (%.1f)|", rsiVal); }
   else                              { detail += StringFormat("[0.0] RSI neutral (%.1f)|", rsiVal); }

   // MACD
   if(macdVal > macdSig && macdHistVal > 0)
   { score += 1.5; detail += "[+1.5] MACD cruce ALCISTA|"; }
   else if(macdVal < macdSig && macdHistVal < 0)
   { score -= 1.5; detail += "[-1.5] MACD cruce BAJISTA|"; }

   // Delta volumen
   if(deltaPct > 30)       { score += 1.0; detail += StringFormat("[+1.0] Delta comprador fuerte (%.0f%%)|", deltaPct); }
   else if(deltaPct < -30) { score -= 1.0; detail += StringFormat("[-1.0] Delta vendedor fuerte (%.0f%%)|", deltaPct); }

   // Patrones de velas
   for(int i = 0; i < cCount; i++)
   {
      if(cDirs[i] == "BULLISH")      { score += 1.0; detail += StringFormat("[+1.0] Patrón BULLISH: %s|", cNames[i]); }
      else if(cDirs[i] == "BEARISH") { score -= 1.0; detail += StringFormat("[-1.0] Patrón BEARISH: %s|", cNames[i]); }
   }

   // Estructura SMC
   for(int i = 0; i < smcCount; i++)
   {
      if(smcDirs[i] == "BULLISH")      { score += 1.5; detail += StringFormat("[+1.5] SMC BULLISH: %s|", smcNames[i]); }
      else if(smcDirs[i] == "BEARISH") { score -= 1.5; detail += StringFormat("[-1.5] SMC BEARISH: %s|", smcNames[i]); }
   }

   // FVG cercanos
   for(int i = 0; i < fvgCount; i++)
   {
      double dist = MathAbs(price - fvgMid[i]);
      if(dist < atr)
      {
         if(fvgType[i] == "Bullish" && price > fvgMid[i])
         { score += 1.0; detail += StringFormat("[+1.0] FVG Bullish cercano (%.0f)|", fvgMid[i]); }
         else if(fvgType[i] == "Bearish" && price < fvgMid[i])
         { score -= 1.0; detail += StringFormat("[-1.0] FVG Bearish cercano (%.0f)|", fvgMid[i]); }
      }
   }

   // Proximidad S/R
   if(supCount > 0 && MathAbs(price - supports[0]) < atr * 0.5)
   { score += 0.5; detail += StringFormat("[+0.5] Cerca soporte (%.0f)|", supports[0]); }
   if(resCount > 0 && MathAbs(price - resistances[0]) < atr * 0.5)
   { score -= 0.5; detail += StringFormat("[-0.5] Cerca resistencia (%.0f)|", resistances[0]); }

   // Clamp
   score = MathMax(-10.0, MathMin(10.0, score));
}

//+------------------------------------------------------------------+
//| IMPRIMIR REPORTE EN JOURNAL                                     |
//+------------------------------------------------------------------+
void PrintAnalysisReport(double price, double atr,
                         double ef, double em, double es, double et,
                         double rsiVal, double macdVal, double macdSig, double macdH,
                         double deltaPct, double delta, double buyVol, double sellVol,
                         string signal, double score, int confidence,
                         double sl, double tp, double slPts, double tpPts, double rr,
                         double riskAmount, double balance,
                         double &supports[], int supCount,
                         double &resistances[], int resCount,
                         string &fvgType[], double &fvgTop[], double &fvgBottom[],
                         double &fvgMid[], int fvgCount,
                         string &cNames[], string &cDirs[], int cCount,
                         string &smcNames[], string &smcDirs[], string &smcDescs[], int smcCount,
                         string detail)
{
   string sep = "─────────────────────────────────────────────────────";
   Print(sep);
   Print(StringFormat("  📊 PRECIO ACTUAL : %.2f  |  ATR: %.2f", price, atr));
   Print(StringFormat("  🎯 SEÑAL         : %s  |  Score: %+.1f/10  |  Confianza: %d%%", signal, score, confidence));
   Print(sep);
   Print(StringFormat("  EMA%d: %.2f  EMA%d: %.2f  EMA%d: %.2f  EMA%d: %.2f",
         InpEMAFast, ef, InpEMAMid, em, InpEMASlow, es, InpEMATrend, et));
   Print(StringFormat("  RSI: %.2f  |  MACD: %.4f  |  Signal: %.4f  |  Hist: %.4f",
         rsiVal, macdVal, macdSig, macdH));
   Print(StringFormat("  VOL Delta: %+.1f%%  |  BuyVol: %.0f  |  SellVol: %.0f",
         deltaPct, buyVol, sellVol));
   Print(sep);

   Print("  S/R LEVELS:");
   for(int i = 0; i < resCount; i++)
      Print(StringFormat("    🔴 Resistencia #%d : %.2f  (+%.2f pts)", i+1, resistances[i], resistances[i]-price));
   Print(StringFormat("    ⚪ PRECIO          : %.2f  ◄", price));
   for(int i = 0; i < supCount; i++)
      Print(StringFormat("    🟢 Soporte    #%d : %.2f  (-%.2f pts)", i+1, supports[i], price-supports[i]));
   Print(sep);

   if(fvgCount > 0)
   {
      Print("  FAIR VALUE GAPS:");
      for(int i = 0; i < fvgCount; i++)
         Print(StringFormat("    [%s FVG]  %.0f – %.0f  (mid: %.0f)", fvgType[i], fvgBottom[i], fvgTop[i], fvgMid[i]));
      Print(sep);
   }

   if(cCount > 0)
   {
      Print("  PATRONES DE VELAS:");
      for(int i = 0; i < cCount; i++)
         Print(StringFormat("    ▶ %-22s [%s]", cNames[i], cDirs[i]));
      Print(sep);
   }

   if(smcCount > 0)
   {
      Print("  ESTRUCTURA SMC:");
      for(int i = 0; i < smcCount; i++)
         Print(StringFormat("    ▶ %-20s [%s]  %s", smcNames[i], smcDirs[i], smcDescs[i]));
      Print(sep);
   }

   Print("  ANÁLISIS DETALLADO (Score):");
   string parts[];
   int n = StringSplit(detail, '|', parts);
   for(int i = 0; i < n; i++)
      if(StringLen(parts[i]) > 2) Print("    " + parts[i]);
   Print(sep);

   if(signal != "ESPERAR")
   {
      Print("  GESTIÓN DE RIESGO:");
      Print(StringFormat("    Entrada : %.2f", price));
      Print(StringFormat("    TP      : %.2f  (+%.2f pts)", tp, tpPts));
      Print(StringFormat("    SL      : %.2f  (-%.2f pts)", sl, slPts));
      Print(StringFormat("    R:R     : 1 : %.2f", rr));
      Print(StringFormat("    Balance : $%.2f  |  Riesgo: $%.2f (%.1f%%)", balance, riskAmount, InpRiskPct));
      Print(sep);
   }
}

//+------------------------------------------------------------------+
//| EXPORTAR CSV                                                     |
//+------------------------------------------------------------------+
void ExportCSV(const MqlRates &rates[], int total,
               double price, double atr,
               double &ef[], double &em[], double &es[], double &et[],
               double &rsi[], double &macdMain[], double &macdSig[], double &macdH[],
               string signal, double score, int confidence,
               double sl, double tp, double slPts, double tpPts, double rr,
               double riskAmount, double balance,
               double &supports[], int supCount,
               double &resistances[], int resCount,
               string &fvgType[], double &fvgTop[], double &fvgBottom[], double &fvgMid[], int fvgCount,
               string &cNames[], string &cDirs[], int cCount,
               string &smcNames[], string &smcDirs[], string &smcDescs[], int smcCount,
               double buyVol, double sellVol, double deltaPct)
{
   string ts       = TimeToString(TimeCurrent(), TIME_DATE|TIME_MINUTES);
   string filename = InpCSVFileName + "_" +
                     StringReplace(TimeToString(TimeCurrent(), TIME_DATE), ".", "") + ".csv";

   int fh = FileOpen(filename, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE)
   {
      Print("❌ No se pudo crear el archivo CSV: ", GetLastError());
      return;
   }

   //── SECCIÓN 1: RESUMEN EJECUTIVO ──────────────────────────────
   FileWrite(fh, "=== RESUMEN EJECUTIVO ===");
   FileWrite(fh, "Campo", "Valor");
   FileWrite(fh, "Timestamp",           ts);
   FileWrite(fh, "Símbolo",             InpSymbol);
   FileWrite(fh, "Temporalidad",        "M5");
   FileWrite(fh, "Precio Actual",       DoubleToString(price, 2));
   FileWrite(fh, "ATR(14)",             DoubleToString(atr, 2));
   FileWrite(fh, "SEÑAL",               signal);
   FileWrite(fh, "Score (-10 a +10)",   DoubleToString(score, 2));
   FileWrite(fh, "Confianza (%)",       IntegerToString(confidence));
   FileWrite(fh, "");

   //── SECCIÓN 2: INDICADORES TÉCNICOS ───────────────────────────
   FileWrite(fh, "=== INDICADORES TÉCNICOS ===");
   FileWrite(fh, "Indicador", "Valor", "Vs Precio");
   FileWrite(fh, StringFormat("EMA%d",  InpEMAFast),  DoubleToString(ef[0],2), price>ef[0]?"PRECIO SOBRE":"PRECIO BAJO");
   FileWrite(fh, StringFormat("EMA%d",  InpEMAMid),   DoubleToString(em[0],2), price>em[0]?"PRECIO SOBRE":"PRECIO BAJO");
   FileWrite(fh, StringFormat("EMA%d",  InpEMASlow),  DoubleToString(es[0],2), price>es[0]?"PRECIO SOBRE":"PRECIO BAJO");
   FileWrite(fh, StringFormat("EMA%d",  InpEMATrend), DoubleToString(et[0],2), price>et[0]?"PRECIO SOBRE":"PRECIO BAJO");
   FileWrite(fh, StringFormat("RSI(%d)",InpRSIPeriod),DoubleToString(rsi[0],2),
             rsi[0]>InpRSIOverbought?"SOBRECOMPRADO":(rsi[0]<InpRSIOversold?"SOBREVENDIDO":"NEUTRAL"));
   FileWrite(fh, "MACD",    DoubleToString(macdMain[0],4), macdMain[0]>macdSig[0]?"ALCISTA":"BAJISTA");
   FileWrite(fh, "MACD Signal", DoubleToString(macdSig[0],4), "");
   FileWrite(fh, "MACD Hist",   DoubleToString(macdH[0],4),   macdH[0]>0?"POSITIVO":"NEGATIVO");
   FileWrite(fh, "");

   //── SECCIÓN 3: VOLUMEN DELTA ───────────────────────────────────
   FileWrite(fh, "=== VOLUMEN DELTA (20 velas) ===");
   FileWrite(fh, "Métrica", "Valor");
   FileWrite(fh, "Volumen Comprador", DoubleToString(buyVol, 0));
   FileWrite(fh, "Volumen Vendedor",  DoubleToString(sellVol, 0));
   FileWrite(fh, "Delta",             DoubleToString(buyVol-sellVol, 0));
   FileWrite(fh, "Delta %",           DoubleToString(deltaPct, 2));
   FileWrite(fh, "Presión",           deltaPct>30?"COMPRADORA FUERTE":(deltaPct<-30?"VENDEDORA FUERTE":"NEUTRAL"));
   FileWrite(fh, "");

   //── SECCIÓN 4: SOPORTE / RESISTENCIA ──────────────────────────
   FileWrite(fh, "=== SOPORTE / RESISTENCIA ===");
   FileWrite(fh, "Tipo", "Nivel", "Distancia (pts)");
   for(int i = 0; i < resCount; i++)
      FileWrite(fh, StringFormat("Resistencia #%d",i+1), DoubleToString(resistances[i],2),
                DoubleToString(resistances[i]-price, 2));
   FileWrite(fh, "PRECIO ACTUAL", DoubleToString(price,2), "0");
   for(int i = 0; i < supCount; i++)
      FileWrite(fh, StringFormat("Soporte #%d",i+1), DoubleToString(supports[i],2),
                DoubleToString(price-supports[i], 2));
   FileWrite(fh, "");

   //── SECCIÓN 5: FAIR VALUE GAPS ────────────────────────────────
   FileWrite(fh, "=== FAIR VALUE GAPS ===");
   FileWrite(fh, "Tipo", "Bottom", "Top", "Mid", "Dist al precio");
   for(int i = 0; i < fvgCount; i++)
      FileWrite(fh, fvgType[i],
                DoubleToString(fvgBottom[i],2), DoubleToString(fvgTop[i],2),
                DoubleToString(fvgMid[i],2),    DoubleToString(MathAbs(price-fvgMid[i]),2));
   if(fvgCount == 0) FileWrite(fh, "Sin FVGs detectados en el rango analizado","","","","");
   FileWrite(fh, "");

   //── SECCIÓN 6: PATRONES DE VELAS ──────────────────────────────
   FileWrite(fh, "=== PATRONES DE VELAS ===");
   FileWrite(fh, "Patrón", "Dirección");
   for(int i = 0; i < cCount; i++)
      FileWrite(fh, cNames[i], cDirs[i]);
   if(cCount == 0) FileWrite(fh, "Sin patrones detectados en vela actual","");
   FileWrite(fh, "");

   //── SECCIÓN 7: ESTRUCTURA SMC ─────────────────────────────────
   FileWrite(fh, "=== ESTRUCTURA DE MERCADO (SMC) ===");
   FileWrite(fh, "Señal", "Dirección", "Descripción");
   for(int i = 0; i < smcCount; i++)
      FileWrite(fh, smcNames[i], smcDirs[i], smcDescs[i]);
   if(smcCount == 0) FileWrite(fh, "Sin estructura SMC detectada","","");
   FileWrite(fh, "");

   //── SECCIÓN 8: GESTIÓN DE RIESGO ──────────────────────────────
   FileWrite(fh, "=== GESTIÓN DE RIESGO ===");
   FileWrite(fh, "Campo", "Valor");
   FileWrite(fh, "Señal",              signal);
   FileWrite(fh, "Precio Entrada",     DoubleToString(price, 2));
   FileWrite(fh, "Take Profit",        signal!="ESPERAR"?DoubleToString(tp,2):"N/A");
   FileWrite(fh, "Stop Loss",          signal!="ESPERAR"?DoubleToString(sl,2):"N/A");
   FileWrite(fh, "TP Puntos",          DoubleToString(tpPts, 2));
   FileWrite(fh, "SL Puntos",          DoubleToString(slPts, 2));
   FileWrite(fh, "Ratio R:R",          StringFormat("1 : %.2f", rr));
   FileWrite(fh, "Balance Cuenta",     StringFormat("$%.2f", balance));
   FileWrite(fh, StringFormat("Riesgo (%.1f%%)", InpRiskPct), StringFormat("$%.2f", riskAmount));
   FileWrite(fh, "");

   //── SECCIÓN 9: HISTÓRICO M5 (últimas 50 velas) ────────────────
   FileWrite(fh, "=== HISTÓRICO M5 - ÚLTIMAS 50 VELAS ===");
   FileWrite(fh, "Fecha/Hora","Open","High","Low","Close","Volumen",
             StringFormat("EMA%d",InpEMAFast), StringFormat("EMA%d",InpEMAMid),
             StringFormat("EMA%d",InpEMASlow), StringFormat("EMA%d",InpEMATrend),
             "RSI","MACD","MACD_Hist","ATR");

   int exportBars = MathMin(50, total);
   for(int i = 0; i < exportBars; i++)
   {
      string t = TimeToString(rates[i].time, TIME_DATE|TIME_MINUTES);
      double macdHistVal = (i < ArraySize(macdMain) && i < ArraySize(macdSig)) ?
                            macdMain[i] - macdSig[i] : 0.0;
      FileWrite(fh, t,
                DoubleToString(rates[i].open,  2), DoubleToString(rates[i].high,  2),
                DoubleToString(rates[i].low,   2), DoubleToString(rates[i].close, 2),
                IntegerToString((int)rates[i].tick_volume),
                (i<ArraySize(ef)?DoubleToString(ef[i],2):""),
                (i<ArraySize(em)?DoubleToString(em[i],2):""),
                (i<ArraySize(es)?DoubleToString(es[i],2):""),
                (i<ArraySize(et)?DoubleToString(et[i],2):""),
                (i<ArraySize(rsi)?DoubleToString(rsi[i],2):""),
                (i<ArraySize(macdMain)?DoubleToString(macdMain[i],4):""),
                DoubleToString(macdHistVal,4),
                (i<ArraySize(atrBuf)?DoubleToString(atrBuf[i],2):""));
   }

   FileClose(fh);
   Print(StringFormat("✅ CSV exportado: %s  (en MQL5/Files/)", filename));
}

//+------------------------------------------------------------------+
//| Utility: reemplazar caracteres en string                        |
//+------------------------------------------------------------------+
string StringReplace(string str, string search, string replace)
{
   string result = str;
   int pos = StringFind(result, search);
   while(pos >= 0)
   {
      result = StringSubstr(result, 0, pos) + replace +
               StringSubstr(result, pos + StringLen(search));
      pos = StringFind(result, search, pos + StringLen(replace));
   }
   return result;
}
