   FileWrite(fh, "SL Puntos",          DoubleToString(slPts, 2));
   FileWrite(fh, "Ratio R:R",          StringFormat("1 : %.2f", rr));
   FileWrite(fh, "Balance Cuenta",     StringFormat("$%.2f", balance));
   FileWrite(fh, StringFormat("Riesgo (%.1f%%)", InpRiskPct), StringFormat("$%.2f", riskAmount));
   FileWrite(fh, "");

   //── SECCIÓN 9: HISTÓRICO M5 (últimas 50 velas) ────────────────
