int OnInit()
{
   //--- Crear handles
   hEMAFast  = iMA(InpSymbol, PERIOD_M5, InpEMAFast,  0, MODE_EMA, PRICE_CLOSE);
   hEMAMid   = iMA(InpSymbol, PERIOD_M5, InpEMAMid,   0, MODE_EMA, PRICE_CLOSE);
   hEMASlow  = iMA(InpSymbol, PERIOD_M5, InpEMASlow,  0, MODE_EMA, PRICE_CLOSE);
   hEMATrend = iMA(InpSymbol, PERIOD_M5, InpEMATrend, 0, MODE_EMA, PRICE_CLOSE);
   hRSI      = iRSI(InpSymbol, PERIOD_M5, InpRSIPeriod, PRICE_CLOSE);
   hMACD     = iMACD(InpSymbol, PERIOD_M5, InpMACDFast, InpMACDSlow, InpMACDSignal, PRICE_CLOSE);
   hATR      = iATR(InpSymbol, PERIOD_M5, InpATRPeriod);

   if(hEMAFast==INVALID_HANDLE || hEMAMid==INVALID_HANDLE ||
