//+------------------------------------------------------------------+
//|                         US30_EA.mq5                             |
//|          EA Automático US30 M5 - Estrategia Optimizada          |
//|                                                                  |
//|  ESTRATEGIA: EMA Cross Trend + MACD Momentum + FVG Entry        |
//|                                                                  |
//|  LÓGICA:                                                         |
//|   1. FILTRO DE TENDENCIA  : EMA9 > EMA21 > EMA50 (alcista)      |
//|                           : EMA9 < EMA21 < EMA50 (bajista)      |
//|   2. FILTRO DE MOMENTUM   : MACD Histograma en dirección trend   |
//|   3. ENTRADA PRECISA      : Precio dentro o tocando FVG válido   |
//|   4. CONFIRMACIÓN VELA    : Vela de confirmación en dirección    |
//|   5. GESTIÓN              : SL = ATR*1.5 | TP = ATR*3.0 (R:R 2) |
//|   6. TRAILING STOP        : ATR dinámico tras alcanzar 1R        |
//|   7. BREAK EVEN           : Mueve SL a entrada al alcanzar 1R   |
//|   8. MAX OPERACIONES/DÍA  : Configurable                        |
//|   9. FILTRO HORARIO       : Sesiones NY y Londres               |
//|  10. REPORTE CSV          : Métricas completas por operación     |
//|                                                                  |
//|  MÉTRICAS MONITOREADAS:                                          |
//|   - Win Rate (%)                                                 |
//|   - Profit Factor                                                |
//|   - Max Drawdown (%)                                             |
//|   - Sharpe Ratio (aproximado)                                    |
//+------------------------------------------------------------------+

#property copyright "US30 EA v1.0 - Estrategia EMA+MACD+FVG"
#property version   "1.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

CTrade         trade;
CPositionInfo  posInfo;

//─────────────────────────────────────────────
// INPUTS - ESTRATEGIA
//─────────────────────────────────────────────
input group "═══ SÍMBOLO Y TEMPORALIDAD ═══"
input string   InpSymbol          = "";       // Símbolo (vacío = gráfico actual)
input bool     InpDebugMode       = true;     // Modo debug (muestra logs detallados)

input group "═══ FILTRO DE TENDENCIA - EMAs ═══"
input int      InpEMA9            = 9;        // EMA rápida
input int      InpEMA21           = 21;       // EMA media
input int      InpEMA50           = 50;       // EMA lenta (filtro tendencia)
input int      InpEMA200          = 200;      // EMA macro tendencia
input bool     InpUseEMA200Filter = true;     // Usar EMA200 como filtro macro

input group "═══ FILTRO DE MOMENTUM - MACD ═══"
input int      InpMACDFast        = 12;       // MACD período rápido
input int      InpMACDSlow        = 26;       // MACD período lento
input int      InpMACDSignal      = 9;        // MACD señal
input double   InpMACDMinHist     = 2.0;      // Histograma mínimo para señal válida

input group "═══ ENTRADA - FAIR VALUE GAP ═══"
input int      InpFVGLookback     = 30;       // Velas atrás para buscar FVG
input double   InpFVGMinSize      = 5.0;      // Tamaño mínimo FVG en puntos
input double   InpFVGMaxDist      = 30.0;     // Distancia máxima al FVG (ATR * factor)
input bool     InpRequireFVG      = true;     // Requerir FVG para entrar (false = solo EMA+MACD)

input group "═══ GESTIÓN DE RIESGO ═══"
input double   InpRiskPercent     = 1.0;      // Riesgo por operación (% balance)
input double   InpSLMultATR       = 1.5;      // Stop Loss = ATR * este valor
input double   InpTPMultATR       = 3.0;      // Take Profit = ATR * este valor
input bool     InpUseBreakEven    = true;     // Activar Break Even
input double   InpBEAtRR          = 1.0;      // Mover SL a BE cuando alcanza R:R = X
input bool     InpUseTrailing     = true;     // Activar Trailing Stop
input double   InpTrailATRMult    = 1.0;      // Trailing = ATR * este valor
input int      InpATRPeriod       = 14;       // Período ATR
input int      InpMaxTrades       = 1;        // Máx operaciones simultáneas
input int      InpMaxTradesDay    = 2;        // Máx operaciones por día

input group "═══ FILTRO HORARIO (hora servidor) ═══"
input bool     InpUseTimeFilter   = true;     // Activar filtro horario
input int      InpLondonStart     = 8;        // Inicio sesión Londres (hora)
input int      InpLondonEnd       = 12;       // Fin sesión Londres
input int      InpNYStart         = 13;       // Inicio sesión NY
input int      InpNYEnd           = 20;       // Fin sesión NY

input group "═══ REPORTE CSV ═══"
input string   InpCSVName         = "US30_EA_Trades"; // Nombre base CSV
input bool     InpSaveCSV         = true;     // Guardar reporte CSV

//─────────────────────────────────────────────
// VARIABLES GLOBALES
//─────────────────────────────────────────────
string   gSymbol       = "";
int      hEMA9, hEMA21, hEMA50, hEMA200;
int      hMACD, hATR;

// Buffers
double   bEMA9[], bEMA21[], bEMA50[], bEMA200[];
double   bMACDMain[], bMACDSig[], bMACDHist[];
double   bATR[];

// Control de trades
datetime gLastBarTime  = 0;
int      gTradesToday  = 0;
datetime gLastTradeDay = 0;
ulong    gOpenTicket   = 0;

// Métricas de rendimiento
int      gTotalTrades  = 0;
int      gWinTrades    = 0;
int      gLossTrades   = 0;
double   gTotalProfit  = 0;
double   gTotalLoss    = 0;
double   gMaxEquity    = 0;
double   gMaxDrawdown  = 0;
double   gInitBalance  = 0;
double   gProfits[];   // array de P&L por trade para Sharpe

// Estado Break Even y Trailing por ticket
ulong    gBETicket     = 0;
bool     gBEActivated  = false;

//─────────────────────────────────────────────
// INICIALIZACIÓN
//─────────────────────────────────────────────
int OnInit()
{
   gSymbol = (StringLen(InpSymbol) > 0) ? InpSymbol : Symbol();

   if(!SymbolSelect(gSymbol, true))
   {
      Print("❌ Símbolo no encontrado: ", gSymbol);
      gSymbol = Symbol();
   }

   // Crear handles
   hEMA9   = iMA(gSymbol, PERIOD_M5, InpEMA9,   0, MODE_EMA, PRICE_CLOSE);
   hEMA21  = iMA(gSymbol, PERIOD_M5, InpEMA21,  0, MODE_EMA, PRICE_CLOSE);
   hEMA50  = iMA(gSymbol, PERIOD_M5, InpEMA50,  0, MODE_EMA, PRICE_CLOSE);
   hEMA200 = iMA(gSymbol, PERIOD_M5, InpEMA200, 0, MODE_EMA, PRICE_CLOSE);
   hMACD   = iMACD(gSymbol, PERIOD_M5, InpMACDFast, InpMACDSlow, InpMACDSignal, PRICE_CLOSE);
   hATR    = iATR(gSymbol, PERIOD_M5, InpATRPeriod);

   if(hEMA9==INVALID_HANDLE || hEMA21==INVALID_HANDLE || hEMA50==INVALID_HANDLE ||
      hEMA200==INVALID_HANDLE || hMACD==INVALID_HANDLE || hATR==INVALID_HANDLE)
   {
      Print("❌ Error creando handles: ", GetLastError());
      return INIT_FAILED;
   }

   ArraySetAsSeries(bEMA9,    true);
   ArraySetAsSeries(bEMA21,   true);
   ArraySetAsSeries(bEMA50,   true);
   ArraySetAsSeries(bEMA200,  true);
   ArraySetAsSeries(bMACDMain,true);
   ArraySetAsSeries(bMACDSig, true);
   ArraySetAsSeries(bMACDHist,true);
   ArraySetAsSeries(bATR,     true);

   trade.SetExpertMagicNumber(202601);
   trade.SetDeviationInPoints(30);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   gInitBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   gMaxEquity   = gInitBalance;

   // Inicializar CSV
   if(InpSaveCSV) InitCSV();

   Print("✅ US30 EA iniciado | Símbolo: ", gSymbol, " | Balance: $", gInitBalance);
   return INIT_SUCCEEDED;
}

//─────────────────────────────────────────────
// DEINIT - guardar reporte final
//─────────────────────────────────────────────
void OnDeinit(const int reason)
{
   if(InpSaveCSV) SaveFinalReport();

   IndicatorRelease(hEMA9);
   IndicatorRelease(hEMA21);
   IndicatorRelease(hEMA50);
   IndicatorRelease(hEMA200);
   IndicatorRelease(hMACD);
   IndicatorRelease(hATR);

   Print("🔌 EA desconectado. Trades totales: ", gTotalTrades,
         " | WinRate: ", WinRate(), "%",
         " | PF: ", ProfitFactor());
}

//─────────────────────────────────────────────
// TICK PRINCIPAL
//─────────────────────────────────────────────
void OnTick()
{
   // Solo procesar en nueva vela M5
   datetime barTime[];
   ArraySetAsSeries(barTime, true);
   if(CopyTime(gSymbol, PERIOD_M5, 0, 1, barTime) < 1) return;
   if(barTime[0] == gLastBarTime) 
   {
      // Gestión continua (BE y Trailing) en cada tick
      ManageOpenTrade();
      return;
   }
   gLastBarTime = barTime[0];

   // Actualizar contador diario
   UpdateDailyCounter();

   // Copiar indicadores (3 velas: 0=actual, 1=anterior, 2=antes)
   if(CopyBuffer(hEMA9,   0, 0, 3, bEMA9)   < 3) return;
   if(CopyBuffer(hEMA21,  0, 0, 3, bEMA21)  < 3) return;
   if(CopyBuffer(hEMA50,  0, 0, 3, bEMA50)  < 3) return;
   if(CopyBuffer(hEMA200, 0, 0, 3, bEMA200) < 3) return;
   if(CopyBuffer(hMACD,   0, 0, 3, bMACDMain) < 3) return;
   if(CopyBuffer(hMACD,   1, 0, 3, bMACDSig)  < 3) return;
   if(CopyBuffer(hATR,    0, 0, 3, bATR)    < 3) return;

   // Calcular histograma
   ArrayResize(bMACDHist, 3);
   for(int i = 0; i < 3; i++)
      bMACDHist[i] = bMACDMain[i] - bMACDSig[i];

   // Verificar condiciones para nueva operación
   if(CountOpenTrades() < InpMaxTrades && gTradesToday < InpMaxTradesDay)
      CheckForEntry();
}

//─────────────────────────────────────────────
// VERIFICAR ENTRADA
//─────────────────────────────────────────────
void CheckForEntry()
{
   // Filtro horario
   if(InpUseTimeFilter && !IsValidSession()) return;

   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   int copied = CopyRates(gSymbol, PERIOD_M5, 0, InpFVGLookback + 5, rates);
   if(copied < 5) return;

   double price = rates[1].close; // Cierre de vela confirmada
   double atr   = bATR[1];

   //── CONDICIÓN ALCISTA ─────────────────────
   bool bullTrend  = (bEMA9[1] > bEMA21[1] && bEMA21[1] > bEMA50[1]);
   bool bullMacro  = (!InpUseEMA200Filter || price > bEMA200[1]);
   bool bullMACDCross = (bMACDHist[1] > 0 && bMACDHist[2] <= 0);  // cruce al alza
   bool bullMACDMom   = (bMACDHist[1] > InpMACDMinHist);
   bool bullCandle = (rates[1].close > rates[1].open);              // vela alcista

   //── CONDICIÓN BAJISTA ─────────────────────
   bool bearTrend  = (bEMA9[1] < bEMA21[1] && bEMA21[1] < bEMA50[1]);
   bool bearMacro  = (!InpUseEMA200Filter || price < bEMA200[1]);
   bool bearMACDCross = (bMACDHist[1] < 0 && bMACDHist[2] >= 0);  // cruce a la baja
   bool bearMACDMom   = (bMACDHist[1] < -InpMACDMinHist);
   bool bearCandle = (rates[1].close < rates[1].open);

   //── BUSCAR FVG ────────────────────────────
   bool bullFVGNear = false, bearFVGNear = false;
   double fvgLevel = 0;

   if(InpRequireFVG)
   {
      FindNearestFVG(rates, copied, price, atr, bullFVGNear, bearFVGNear, fvgLevel);
   }
   else
   {
      bullFVGNear = true;
      bearFVGNear = true;
   }

   //── SEÑAL LONG ────────────────────────────
   bool longSignal = bullTrend && bullMacro && (bullMACDCross || bullMACDMom) && bullCandle && bullFVGNear;

   //── SEÑAL SHORT ───────────────────────────
   bool shortSignal = bearTrend && bearMacro && (bearMACDCross || bearMACDMom) && bearCandle && bearFVGNear;

   if(InpDebugMode)
   {
      if(bullTrend || bearTrend)
         Print(StringFormat(
            "📊 Análisis vela | Trend: %s | MACD Cross: %s/%s | MACD Mom: %s/%s | FVG: %s/%s | Señal: %s",
            bullTrend?"BULL":(bearTrend?"BEAR":"NONE"),
            bullMACDCross?"✅":"❌", bearMACDCross?"✅":"❌",
            bullMACDMom?"✅":"❌",  bearMACDMom?"✅":"❌",
            bullFVGNear?"✅":"❌",  bearFVGNear?"✅":"❌",
            longSignal?"LONG":(shortSignal?"SHORT":"WAIT")));
   }

   if(longSignal)  OpenTrade(ORDER_TYPE_BUY,  atr, rates[1]);
   else if(shortSignal) OpenTrade(ORDER_TYPE_SELL, atr, rates[1]);
}

//─────────────────────────────────────────────
// BUSCAR FVG MÁS CERCANO AL PRECIO
//─────────────────────────────────────────────
void FindNearestFVG(const MqlRates &rates[], int total,
                    double price, double atr,
                    bool &bullNear, bool &bearNear, double &level)
{
   bullNear = false;
   bearNear = false;
   double maxDist = atr * InpFVGMaxDist / 10.0;

   for(int i = 2; i < total - 1 && i < InpFVGLookback; i++)
   {
      double fvgSize = 0;
      double fvgMid  = 0;

      // Bullish FVG: low[i] > high[i+2]  (arrays invertidos, i=0 es reciente)
      if(rates[i].low > rates[i+2].high)
      {
         fvgSize = rates[i].low - rates[i+2].high;
         fvgMid  = (rates[i].low + rates[i+2].high) / 2.0;
         if(fvgSize >= InpFVGMinSize && MathAbs(price - fvgMid) <= maxDist)
         {
            bullNear = true;
            level    = fvgMid;
         }
      }
      // Bearish FVG: high[i] < low[i+2]
      else if(rates[i].high < rates[i+2].low)
      {
         fvgSize = rates[i+2].low - rates[i].high;
         fvgMid  = (rates[i].high + rates[i+2].low) / 2.0;
         if(fvgSize >= InpFVGMinSize && MathAbs(price - fvgMid) <= maxDist)
         {
            bearNear = true;
            level    = fvgMid;
         }
      }
   }
}

//─────────────────────────────────────────────
// ABRIR OPERACIÓN
//─────────────────────────────────────────────
void OpenTrade(ENUM_ORDER_TYPE type, double atr, MqlRates &lastBar)
{
   double price  = (type == ORDER_TYPE_BUY)
                   ? SymbolInfoDouble(gSymbol, SYMBOL_ASK)
                   : SymbolInfoDouble(gSymbol, SYMBOL_BID);

   double sl_pts = atr * InpSLMultATR;
   double tp_pts = atr * InpTPMultATR;

   double sl = (type == ORDER_TYPE_BUY) ? price - sl_pts : price + sl_pts;
   double tp = (type == ORDER_TYPE_BUY) ? price + tp_pts : price - tp_pts;

   // Normalizar precios
   int digits = (int)SymbolInfoInteger(gSymbol, SYMBOL_DIGITS);
   sl = NormalizeDouble(sl, digits);
   tp = NormalizeDouble(tp, digits);

   // Calcular lotaje basado en riesgo
   double lots = CalculateLots(sl_pts);
   if(lots <= 0) { Print("⚠️ Lotaje inválido"); return; }

   string comment = StringFormat("US30EA|%s|FVG|ATR%.0f",
                                  type==ORDER_TYPE_BUY?"BUY":"SELL", atr);

   bool result = (type == ORDER_TYPE_BUY)
                 ? trade.Buy(lots, gSymbol, price, sl, tp, comment)
                 : trade.Sell(lots, gSymbol, price, sl, tp, comment);

   if(result)
   {
      gOpenTicket   = trade.ResultOrder();
      gBETicket     = gOpenTicket;
      gBEActivated  = false;
      gTradesToday++;

      Print(StringFormat("✅ %s abierta | Ticket:%d | Precio:%.2f | SL:%.2f | TP:%.2f | Lots:%.2f | ATR:%.2f",
            type==ORDER_TYPE_BUY?"BUY":"SELL",
            gOpenTicket, price, sl, tp, lots, atr));

      if(InpSaveCSV) LogTradeOpen(gOpenTicket, type, price, sl, tp, lots, atr);
   }
   else
   {
      Print("❌ Error abriendo trade: ", trade.ResultRetcodeDescription());
   }
}

//─────────────────────────────────────────────
// CALCULAR LOTAJE
//─────────────────────────────────────────────
double CalculateLots(double slPoints)
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = balance * (InpRiskPercent / 100.0);
   double tickValue  = SymbolInfoDouble(gSymbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(gSymbol, SYMBOL_TRADE_TICK_SIZE);
   double lotStep    = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_STEP);
   double minLot     = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_MIN);
   double maxLot     = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_MAX);

   if(tickValue == 0 || tickSize == 0 || slPoints == 0) return minLot;

   double valuePerPoint = tickValue / tickSize;
   double lots = riskAmount / (slPoints * valuePerPoint);
   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(minLot, MathMin(maxLot, lots));

   return NormalizeDouble(lots, 2);
}

//─────────────────────────────────────────────
// GESTIÓN DE TRADE ABIERTO (Break Even + Trailing)
//─────────────────────────────────────────────
void ManageOpenTrade()
{
   if(gOpenTicket == 0) return;
   if(!posInfo.SelectByTicket(gOpenTicket)) { gOpenTicket = 0; return; }

   double currentPrice = posInfo.PriceCurrent();
   double openPrice    = posInfo.PriceOpen();
   double currentSL    = posInfo.StopLoss();
   double currentTP    = posInfo.TakeProfit();
   ENUM_POSITION_TYPE posType = posInfo.PositionType();

   // ATR actual
   if(CopyBuffer(hATR, 0, 0, 2, bATR) < 2) return;
   double atr     = bATR[0];
   double slDist  = atr * InpSLMultATR;
   double beDist  = slDist * InpBEAtRR;  // distancia para activar BE

   int    digits  = (int)SymbolInfoInteger(gSymbol, SYMBOL_DIGITS);

   //── BREAK EVEN ────────────────────────────
   if(InpUseBreakEven && !gBEActivated)
   {
      bool beTriggered = false;
      if(posType == POSITION_TYPE_BUY  && currentPrice >= openPrice + beDist) beTriggered = true;
      if(posType == POSITION_TYPE_SELL && currentPrice <= openPrice - beDist) beTriggered = true;

      if(beTriggered)
      {
         double newSL = NormalizeDouble(openPrice, digits);
         if((posType == POSITION_TYPE_BUY  && newSL > currentSL) ||
            (posType == POSITION_TYPE_SELL && newSL < currentSL))
         {
            if(trade.PositionModify(gOpenTicket, newSL, currentTP))
            {
               gBEActivated = true;
               Print(StringFormat("🔒 Break Even activado | Ticket:%d | SL movido a %.2f", gOpenTicket, newSL));
            }
         }
      }
   }

   //── TRAILING STOP ─────────────────────────
   if(InpUseTrailing && gBEActivated)
   {
      double trailDist = atr * InpTrailATRMult;
      double newSL     = 0;

      if(posType == POSITION_TYPE_BUY)
      {
         newSL = NormalizeDouble(currentPrice - trailDist, digits);
         if(newSL > currentSL + SymbolInfoDouble(gSymbol, SYMBOL_POINT))
            trade.PositionModify(gOpenTicket, newSL, currentTP);
      }
      else if(posType == POSITION_TYPE_SELL)
      {
         newSL = NormalizeDouble(currentPrice + trailDist, digits);
         if(newSL < currentSL - SymbolInfoDouble(gSymbol, SYMBOL_POINT))
            trade.PositionModify(gOpenTicket, newSL, currentTP);
      }
   }
}

//─────────────────────────────────────────────
// EVENTO TRADE (cierre de operación)
//─────────────────────────────────────────────
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;

   ulong dealTicket = trans.deal;
   if(dealTicket == 0) return;

   if(!HistoryDealSelect(dealTicket)) return;
   if(HistoryDealGetInteger(dealTicket, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;
   if(HistoryDealGetInteger(dealTicket, DEAL_MAGIC) != 202601) return;

   double pnl     = HistoryDealGetDouble(dealTicket, DEAL_PROFIT)
                  + HistoryDealGetDouble(dealTicket, DEAL_SWAP)
                  + HistoryDealGetDouble(dealTicket, DEAL_COMMISSION);
   double closeP  = HistoryDealGetDouble(dealTicket, DEAL_PRICE);
   string reason  = "";

   gTotalTrades++;
   if(pnl > 0) { gWinTrades++;  gTotalProfit += pnl; reason = "WIN"; }
   else         { gLossTrades++; gTotalLoss   += MathAbs(pnl); reason = "LOSS"; }

   // Registrar en array para Sharpe
   int sz = ArraySize(gProfits);
   ArrayResize(gProfits, sz + 1);
   gProfits[sz] = pnl;

   // Actualizar drawdown
   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   if(equity > gMaxEquity) gMaxEquity = equity;
   double dd = (gMaxEquity - equity) / gMaxEquity * 100.0;
   if(dd > gMaxDrawdown) gMaxDrawdown = dd;

   // Resetear ticket
   if(HistoryDealGetInteger(dealTicket, DEAL_ORDER) == gOpenTicket ||
      gOpenTicket == 0)
      gOpenTicket = 0;

   Print(StringFormat("📋 Trade cerrado | %s | P&L: $%.2f | WR: %.1f%% | PF: %.2f | DD: %.2f%%",
         reason, pnl, WinRate(), ProfitFactor(), gMaxDrawdown));

   if(InpSaveCSV) LogTradeClose(dealTicket, closeP, pnl, reason);
}

//─────────────────────────────────────────────
// FILTRO HORARIO
//─────────────────────────────────────────────
bool IsValidSession()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int h = dt.hour;

   bool london = (h >= InpLondonStart && h < InpLondonEnd);
   bool ny     = (h >= InpNYStart     && h < InpNYEnd);
   return (london || ny);
}

//─────────────────────────────────────────────
// UTILIDADES
//─────────────────────────────────────────────
int CountOpenTrades()
{
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == gSymbol && posInfo.Magic() == 202601)
            count++;
   return count;
}

void UpdateDailyCounter()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00", dt.year, dt.mon, dt.day));
   if(today != gLastTradeDay)
   {
      gTradesToday  = 0;
      gLastTradeDay = today;
   }
}

double WinRate()
{
   if(gTotalTrades == 0) return 0;
   return NormalizeDouble((double)gWinTrades / gTotalTrades * 100.0, 1);
}

double ProfitFactor()
{
   if(gTotalLoss == 0) return (gTotalProfit > 0) ? 99.0 : 0.0;
   return NormalizeDouble(gTotalProfit / gTotalLoss, 2);
}

double SharpeRatio()
{
   int n = ArraySize(gProfits);
   if(n < 2) return 0;

   double sum = 0;
   for(int i = 0; i < n; i++) sum += gProfits[i];
   double mean = sum / n;

   double variance = 0;
   for(int i = 0; i < n; i++) variance += MathPow(gProfits[i] - mean, 2);
   double stddev = MathSqrt(variance / (n - 1));

   if(stddev == 0) return 0;
   return NormalizeDouble(mean / stddev * MathSqrt(252.0), 2); // anualizado
}

//─────────────────────────────────────────────
// CSV - INICIALIZAR
//─────────────────────────────────────────────
void InitCSV()
{
   string filename = InpCSVName + "_Trades.csv";
   int fh = FileOpen(filename, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE) return;

   FileWrite(fh,
