//─────────────────────────────────────────────
// CSV - LOG CIERRE
//─────────────────────────────────────────────
void LogTradeClose(ulong dealTicket, double closePrice, double pnl, string result)
{
   string filename = InpCSVName + "_Trades.csv";
   int fh = FileOpen(filename, FILE_READ|FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE) return;

   FileSeek(fh, 0, SEEK_END);

   // Obtener datos del deal
   string openTime  = TimeToString(HistoryDealGetInteger(dealTicket, DEAL_TIME) - 0, TIME_DATE|TIME_MINUTES);
   string closeTime = TimeToString((datetime)HistoryDealGetInteger(dealTicket, DEAL_TIME), TIME_DATE|TIME_MINUTES);
   string type      = (HistoryDealGetInteger(dealTicket, DEAL_TYPE) == DEAL_TYPE_SELL) ? "BUY" : "SELL";

   FileWrite(fh,
      (string)dealTicket, type,
      openTime, "N/A", "N/A", "N/A", "N/A", "N/A",
      closeTime, DoubleToString(closePrice, 2),
      DoubleToString(pnl, 2), result,
      DoubleToString(WinRate(), 1),
      DoubleToString(ProfitFactor(), 2),
      DoubleToString(gMaxDrawdown, 2),
      DoubleToString(SharpeRatio(), 2),
      DoubleToString(AccountInfoDouble(ACCOUNT_BALANCE), 2));

   FileClose(fh);
}

//─────────────────────────────────────────────
// CSV - REPORTE FINAL DE RENDIMIENTO
//─────────────────────────────────────────────
void SaveFinalReport()
{
   string filename = InpCSVName + "_Performance.csv";
   int fh = FileOpen(filename, FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE) return;

   double finalBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   double netProfit    = finalBalance - gInitBalance;
   double returnPct    = (gInitBalance > 0) ? (netProfit / gInitBalance * 100.0) : 0;

   FileWrite(fh, "=== REPORTE FINAL DE RENDIMIENTO ===");
   FileWrite(fh, "Métrica", "Valor", "Objetivo");
   FileWrite(fh, "");
   FileWrite(fh, "── OPERACIONES ──");
   FileWrite(fh, "Total Trades",    (string)gTotalTrades,  "–");
   FileWrite(fh, "Trades Ganados",  (string)gWinTrades,    "–");
   FileWrite(fh, "Trades Perdidos", (string)gLossTrades,   "–");
   FileWrite(fh, "");
   FileWrite(fh, "── MÉTRICAS CLAVE ──");
   FileWrite(fh, "Win Rate (%)",       DoubleToString(WinRate(), 1),          "> 55%");
   FileWrite(fh, "Profit Factor",      DoubleToString(ProfitFactor(), 2),     "> 1.5");
   FileWrite(fh, "Max Drawdown (%)",   DoubleToString(gMaxDrawdown, 2),       "< 15%");
   FileWrite(fh, "Sharpe Ratio",       DoubleToString(SharpeRatio(), 2),      "> 1.0");
   FileWrite(fh, "");
   FileWrite(fh, "── RESULTADO FINANCIERO ──");
   FileWrite(fh, "Balance Inicial",    DoubleToString(gInitBalance, 2),       "–");
   FileWrite(fh, "Balance Final",      DoubleToString(finalBalance, 2),       "–");
   FileWrite(fh, "Beneficio Neto",     DoubleToString(netProfit, 2),          "> 0");
   FileWrite(fh, "Retorno (%)",        DoubleToString(returnPct, 2),          "–");
   FileWrite(fh, "Ganancia Total",     DoubleToString(gTotalProfit, 2),       "–");
   FileWrite(fh, "Pérdida Total",      DoubleToString(gTotalLoss, 2),         "–");
   FileWrite(fh, "");
   FileWrite(fh, "── EVALUACIÓN ──");
   FileWrite(fh, "Win Rate",     WinRate()>55?"✅ APROBADO":"❌ MEJORAR",   "> 55%");
   FileWrite(fh, "ProfitFactor", ProfitFactor()>1.5?"✅ APROBADO":"❌ MEJORAR","1.5");
   FileWrite(fh, "Drawdown",     gMaxDrawdown<15?"✅ APROBADO":"❌ REVISAR", "< 15%");
   FileWrite(fh, "Sharpe",       SharpeRatio()>1?"✅ APROBADO":"❌ MEJORAR", "> 1.0");

   string overallVerdict = (WinRate()>55 && ProfitFactor()>1.5 && gMaxDrawdown<15 && SharpeRatio()>1)
                           ? "🏆 ESTRATEGIA RENTABLE - APTA PARA LIVE"
                           : "⚠️ ESTRATEGIA REQUIERE OPTIMIZACIÓN";
   FileWrite(fh, "");
   FileWrite(fh, "VEREDICTO FINAL", overallVerdict);

   FileClose(fh);
   Print("📄 Reporte final guardado: ", filename);
}
