//+------------------------------------------------------------------+
//|                       US30_EA_v2.mq5                            |
//|        EA Automático US30 M5 - v2 POST-BACKTEST OPTIMIZADO      |
//|                                                                  |
//|  FIXES v2 (basados en análisis de 602 trades):                  |
//|   FIX #1 - HORARIO MUERTO: Bloquea 13:00-15:59                  |
//|            → Recupera $3,207 perdidos en overlap NY/Londres      |
//|   FIX #2 - FILTRO ADX(14)>25: Solo opera en tendencia real      |
//|            → Elimina meses 37-38% WR en mercados laterales      |
//|   FIX #3 - TP FIJO + Trailing SOLO tras alcanzar TP             |
//|            → Sube ratio W/L de 1.01 a ~1.8                      |
//|                                                                  |
//|  ESTRATEGIA BASE:                                                |
//|   1. ADX > umbral           → mercado en tendencia              |
//|   2. EMA9 > EMA21 > EMA50   → dirección de la tendencia         |
//|   3. Precio vs EMA200       → filtro macro                      |
//|   4. MACD histograma        → momentum confirmado               |
//|   5. FVG cercano            → zona de entrada precisa           |
//|   6. Vela de confirmación   → entrada en cierre de vela M5      |
//|   7. SL = ATR×1.5  TP = ATR×3.0  → R:R 2:1                    |
//|   8. Break Even al alcanzar 1R                                   |
//|   9. Trailing SOLO después de alcanzar TP (protege profits)     |
//|  10. Horario: Londres 08-12 | NY 16-20 (sin overlap muerto)     |
//+------------------------------------------------------------------+

#property copyright "US30 EA v2.0 - Post-Backtest Optimizado"
#property version   "2.00"
#property strict

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>

CTrade         trade;
CPositionInfo  posInfo;

//─────────────────────────────────────────────
// INPUTS
//─────────────────────────────────────────────
input group "═══ SÍMBOLO ═══"
input string   InpSymbol          = "";      // Símbolo (vacío = gráfico actual)
input bool     InpDebugMode       = true;    // Logs detallados en Journal

input group "═══ FIX #2 - FILTRO ADX (TENDENCIA REAL) ═══"
input bool     InpUseADX          = true;    // [FIX #2] Activar filtro ADX
input int      InpADXPeriod       = 14;      // Período ADX
input double   InpADXMin          = 25.0;    // ADX mínimo para operar (>25 = tendencia)

input group "═══ FILTRO DE TENDENCIA - EMAs ═══"
input int      InpEMA9            = 9;       // EMA rápida
input int      InpEMA21           = 21;      // EMA media
input int      InpEMA50           = 50;      // EMA lenta
input int      InpEMA200          = 200;     // EMA macro
input bool     InpUseEMA200Filter = true;    // Filtro EMA200

input group "═══ FILTRO DE MOMENTUM - MACD ═══"
input int      InpMACDFast        = 12;      // MACD rápido
input int      InpMACDSlow        = 26;      // MACD lento
input int      InpMACDSignal      = 9;       // MACD señal
input double   InpMACDMinHist     = 2.0;     // Histograma mínimo

input group "═══ ENTRADA - FAIR VALUE GAP ═══"
input int      InpFVGLookback     = 30;      // Velas para buscar FVG
input double   InpFVGMinSize      = 5.0;     // Tamaño mínimo FVG (pts)
input double   InpFVGMaxDist      = 30.0;    // Distancia máxima al FVG
input bool     InpRequireFVG      = true;    // Requerir FVG para entrar

input group "═══ FIX #3 - GESTIÓN DE RIESGO ═══"
input double   InpRiskPercent     = 1.0;     // Riesgo por operación (% balance)
input double   InpSLMultATR       = 1.5;     // SL = ATR × este valor
input double   InpTPMultATR       = 3.0;     // TP = ATR × este valor (FIJO)
input bool     InpUseBreakEven    = true;    // Activar Break Even
input double   InpBEAtRR          = 1.0;     // BE cuando precio alcanza 1R
input bool     InpUseTrailing     = true;    // [FIX #3] Trailing SOLO tras alcanzar TP
input double   InpTrailATRMult    = 1.5;     // Trailing = ATR × este valor
input int      InpATRPeriod       = 14;      // Período ATR
input int      InpMaxTrades       = 1;       // Máx posiciones simultáneas
input int      InpMaxTradesDay    = 2;       // Máx operaciones por día

input group "═══ FIX #1 - FILTRO HORARIO (hora servidor) ═══"
input bool     InpUseTimeFilter   = true;    // Activar filtro horario
input int      InpLondonStart     = 8;       // [Londres] hora inicio
input int      InpLondonEnd       = 12;      // [Londres] hora fin (hasta las 12:59)
input int      InpNYStart         = 16;      // [FIX #1] NY: ahora desde 16h (antes 13h)
input int      InpNYEnd           = 20;      // [NY] hora fin
// ZONA BLOQUEADA: 13:00 - 15:59 (overlap NY+Londres = caos de señales)

input group "═══ REPORTE CSV ═══"
input string   InpCSVName         = "US30_EA_v2"; // Nombre base CSV
input bool     InpSaveCSV         = true;    // Guardar CSV

//─────────────────────────────────────────────
// VARIABLES GLOBALES
//─────────────────────────────────────────────
string   gSymbol       = "";
int      hEMA9, hEMA21, hEMA50, hEMA200;
int      hMACD, hATR, hADX;

double   bEMA9[], bEMA21[], bEMA50[], bEMA200[];
double   bMACDMain[], bMACDSig[];
double   bATR[], bADX[], bDIPlus[], bDIMinus[];

datetime gLastBarTime  = 0;
int      gTradesToday  = 0;
datetime gLastTradeDay = 0;
ulong    gOpenTicket   = 0;

// Estado gestión
bool     gBEActivated  = false;
bool     gTPReached    = false;   // [FIX #3] flag: precio alcanzó TP una vez
double   gTradeTP      = 0;       // TP original guardado
double   gTradeSL      = 0;       // SL original

// Métricas
int      gTotalTrades  = 0;
int      gWinTrades    = 0;
int      gLossTrades   = 0;
double   gTotalProfit  = 0;
double   gTotalLoss    = 0;
double   gMaxEquity    = 0;
double   gMaxDrawdown  = 0;
double   gInitBalance  = 0;
double   gProfits[];

// Stats por sesión para CSV de análisis
int      gLondonTrades = 0, gLondonWins = 0;
int      gNYTrades     = 0, gNYWins     = 0;
int      gADXFiltered  = 0;   // cuántas señales bloqueó el ADX

//─────────────────────────────────────────────
// INICIALIZACIÓN
//─────────────────────────────────────────────
int OnInit()
{
   gSymbol = (StringLen(InpSymbol) > 0) ? InpSymbol : Symbol();
   if(!SymbolSelect(gSymbol, true)) { gSymbol = Symbol(); }

   hEMA9   = iMA(gSymbol, PERIOD_M5, InpEMA9,   0, MODE_EMA, PRICE_CLOSE);
   hEMA21  = iMA(gSymbol, PERIOD_M5, InpEMA21,  0, MODE_EMA, PRICE_CLOSE);
   hEMA50  = iMA(gSymbol, PERIOD_M5, InpEMA50,  0, MODE_EMA, PRICE_CLOSE);
   hEMA200 = iMA(gSymbol, PERIOD_M5, InpEMA200, 0, MODE_EMA, PRICE_CLOSE);
   hMACD   = iMACD(gSymbol, PERIOD_M5, InpMACDFast, InpMACDSlow, InpMACDSignal, PRICE_CLOSE);
   hATR    = iATR(gSymbol, PERIOD_M5, InpATRPeriod);
   hADX    = iADX(gSymbol, PERIOD_M5, InpADXPeriod);  // [FIX #2]

   if(hEMA9==INVALID_HANDLE || hEMA21==INVALID_HANDLE || hEMA50==INVALID_HANDLE ||
      hEMA200==INVALID_HANDLE || hMACD==INVALID_HANDLE || hATR==INVALID_HANDLE ||
      hADX==INVALID_HANDLE)
   {
      Print("❌ Error creando handles: ", GetLastError());
      return INIT_FAILED;
   }

   ArraySetAsSeries(bEMA9,    true);
   ArraySetAsSeries(bEMA21,   true);
   ArraySetAsSeries(bEMA50,   true);
   ArraySetAsSeries(bEMA200,  true);
   ArraySetAsSeries(bMACDMain,true);
   ArraySetAsSeries(bMACDSig, true);
   ArraySetAsSeries(bATR,     true);
   ArraySetAsSeries(bADX,     true);
   ArraySetAsSeries(bDIPlus,  true);
   ArraySetAsSeries(bDIMinus, true);

   trade.SetExpertMagicNumber(202602);
   trade.SetDeviationInPoints(30);
   trade.SetTypeFilling(ORDER_FILLING_IOC);

   gInitBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   gMaxEquity   = gInitBalance;

   if(InpSaveCSV) InitCSV();

   Print(StringFormat(
      "✅ US30 EA v2 | Símbolo: %s | Balance: $%.2f | ADX>%.0f | Zona muerta: 13-15h bloqueada",
      gSymbol, gInitBalance, InpADXMin));

   return INIT_SUCCEEDED;
}

//─────────────────────────────────────────────
// DEINIT
//─────────────────────────────────────────────
void OnDeinit(const int reason)
{
   if(InpSaveCSV) SaveFinalReport();

   IndicatorRelease(hEMA9);   IndicatorRelease(hEMA21);
   IndicatorRelease(hEMA50);  IndicatorRelease(hEMA200);
   IndicatorRelease(hMACD);   IndicatorRelease(hATR);
   IndicatorRelease(hADX);

   Print(StringFormat(
      "🔌 EA v2 off | Trades: %d | WR: %.1f%% | PF: %.2f | ADX bloqueó: %d señales",
      gTotalTrades, WinRate(), ProfitFactor(), gADXFiltered));
}

//─────────────────────────────────────────────
// TICK PRINCIPAL
//─────────────────────────────────────────────
void OnTick()
{
   datetime barTime[];
   ArraySetAsSeries(barTime, true);
   if(CopyTime(gSymbol, PERIOD_M5, 0, 1, barTime) < 1) return;

   if(barTime[0] == gLastBarTime)
   {
      ManageOpenTrade();
      return;
   }
   gLastBarTime = barTime[0];

   UpdateDailyCounter();

   // Copiar indicadores (4 velas para cruce confirmado)
   if(CopyBuffer(hEMA9,   0, 0, 4, bEMA9)    < 4) return;
   if(CopyBuffer(hEMA21,  0, 0, 4, bEMA21)   < 4) return;
   if(CopyBuffer(hEMA50,  0, 0, 4, bEMA50)   < 4) return;
   if(CopyBuffer(hEMA200, 0, 0, 4, bEMA200)  < 4) return;
   if(CopyBuffer(hMACD,   0, 0, 4, bMACDMain)< 4) return;
   if(CopyBuffer(hMACD,   1, 0, 4, bMACDSig) < 4) return;
   if(CopyBuffer(hATR,    0, 0, 4, bATR)     < 4) return;
   if(CopyBuffer(hADX,    0, 0, 4, bADX)     < 4) return;  // ADX line
   if(CopyBuffer(hADX,    1, 0, 4, bDIPlus)  < 4) return;  // +DI
   if(CopyBuffer(hADX,    2, 0, 4, bDIMinus) < 4) return;  // -DI

   if(CountOpenTrades() < InpMaxTrades && gTradesToday < InpMaxTradesDay)
      CheckForEntry();
}

//─────────────────────────────────────────────
// VERIFICAR ENTRADA
//─────────────────────────────────────────────
void CheckForEntry()
{
   // ── FIX #1: Filtro horario con zona muerta 13-15h ─────────
   if(InpUseTimeFilter && !IsValidSession()) return;

   MqlRates rates[];
   ArraySetAsSeries(rates, true);
   int copied = CopyRates(gSymbol, PERIOD_M5, 0, InpFVGLookback + 5, rates);
   if(copied < 5) return;

   double price   = rates[1].close;
   double atr     = bATR[1];
   double adxVal  = bADX[1];
   double diPlus  = bDIPlus[1];
   double diMinus = bDIMinus[1];

   // ── FIX #2: Filtro ADX — solo operar si hay tendencia real ─
   if(InpUseADX && adxVal < InpADXMin)
   {
      gADXFiltered++;
      if(InpDebugMode && gADXFiltered % 20 == 0)
         Print(StringFormat("🔕 ADX=%.1f < %.0f | %d señales bloqueadas total",
               adxVal, InpADXMin, gADXFiltered));
      return;
   }

   // Histograma MACD
   double histNow  = bMACDMain[1] - bMACDSig[1];
   double histPrev = bMACDMain[2] - bMACDSig[2];

   // ── CONDICIONES ALCISTAS ───────────────────────────────────
   bool bullTrend   = (bEMA9[1] > bEMA21[1] && bEMA21[1] > bEMA50[1]);
   bool bullMacro   = (!InpUseEMA200Filter || price > bEMA200[1]);
   bool bullADX     = (diPlus > diMinus);                            // +DI domina
   bool bullMACDCrs = (histNow > 0 && histPrev <= 0);                // cruce alcista
   bool bullMACDMom = (histNow > InpMACDMinHist);                    // momentum
   bool bullCandle  = (rates[1].close > rates[1].open);

   // ── CONDICIONES BAJISTAS ───────────────────────────────────
   bool bearTrend   = (bEMA9[1] < bEMA21[1] && bEMA21[1] < bEMA50[1]);
   bool bearMacro   = (!InpUseEMA200Filter || price < bEMA200[1]);
   bool bearADX     = (diMinus > diPlus);                            // -DI domina
   bool bearMACDCrs = (histNow < 0 && histPrev >= 0);                // cruce bajista
   bool bearMACDMom = (histNow < -InpMACDMinHist);
   bool bearCandle  = (rates[1].close < rates[1].open);

   // ── FVG ───────────────────────────────────────────────────
   bool bullFVG = false, bearFVG = false;
   double fvgLevel = 0;
   if(InpRequireFVG)
      FindNearestFVG(rates, copied, price, atr, bullFVG, bearFVG, fvgLevel);
   else { bullFVG = true; bearFVG = true; }

   // ── SEÑAL LONG ─────────────────────────────────────────────
   bool longSignal  = bullTrend && bullMacro && bullADX &&
                      (bullMACDCrs || bullMACDMom) && bullCandle && bullFVG;

   // ── SEÑAL SHORT ────────────────────────────────────────────
   bool shortSignal = bearTrend && bearMacro && bearADX &&
                      (bearMACDCrs || bearMACDMom) && bearCandle && bearFVG;

   if(InpDebugMode && (bullTrend || bearTrend))
   {
      string session = GetCurrentSession();
      Print(StringFormat(
         "📊 [%s] ADX:%.1f %s | Trend:%s | MACD:%s/%s | FVG:%s/%s | ▶ %s",
         session, adxVal, adxVal>=InpADXMin?"✅":"🔕",
         bullTrend?"BULL":(bearTrend?"BEAR":"FLAT"),
         bullMACDCrs||bullMACDMom?"✅":"❌",
         bearMACDCrs||bearMACDMom?"✅":"❌",
         bullFVG?"✅":"❌", bearFVG?"✅":"❌",
         longSignal?"LONG":(shortSignal?"SHORT":"WAIT")));
   }

   if(longSignal)       OpenTrade(ORDER_TYPE_BUY,  atr, rates[1]);
   else if(shortSignal) OpenTrade(ORDER_TYPE_SELL, atr, rates[1]);
}

//─────────────────────────────────────────────
// BUSCAR FVG
//─────────────────────────────────────────────
void FindNearestFVG(const MqlRates &rates[], int total,
                    double price, double atr,
                    bool &bullNear, bool &bearNear, double &level)
{
   bullNear = false; bearNear = false;
   double maxDist = atr * InpFVGMaxDist / 10.0;

   for(int i = 2; i < total - 1 && i < InpFVGLookback; i++)
   {
      double fvgMid = 0;

      if(rates[i].low > rates[i+2].high)
      {
         double fvgSize = rates[i].low - rates[i+2].high;
         fvgMid = (rates[i].low + rates[i+2].high) / 2.0;
         if(fvgSize >= InpFVGMinSize && MathAbs(price - fvgMid) <= maxDist)
            { bullNear = true; level = fvgMid; }
      }
      else if(rates[i].high < rates[i+2].low)
      {
         double fvgSize = rates[i+2].low - rates[i].high;
         fvgMid = (rates[i].high + rates[i+2].low) / 2.0;
         if(fvgSize >= InpFVGMinSize && MathAbs(price - fvgMid) <= maxDist)
            { bearNear = true; level = fvgMid; }
      }
   }
}

//─────────────────────────────────────────────
// ABRIR OPERACIÓN
//─────────────────────────────────────────────
void OpenTrade(ENUM_ORDER_TYPE type, double atr, MqlRates &lastBar)
{
   double price  = (type == ORDER_TYPE_BUY)
                   ? SymbolInfoDouble(gSymbol, SYMBOL_ASK)
                   : SymbolInfoDouble(gSymbol, SYMBOL_BID);

   double sl_pts = atr * InpSLMultATR;
   double tp_pts = atr * InpTPMultATR;

   double sl = (type == ORDER_TYPE_BUY) ? price - sl_pts : price + sl_pts;
   double tp = (type == ORDER_TYPE_BUY) ? price + tp_pts : price - tp_pts;

   int digits = (int)SymbolInfoInteger(gSymbol, SYMBOL_DIGITS);
   sl = NormalizeDouble(sl, digits);
   tp = NormalizeDouble(tp, digits);

   double lots = CalculateLots(sl_pts);
   if(lots <= 0) return;

   string session = GetCurrentSession();
   string comment = StringFormat("US30v2|%s|%s|ADX%.0f|ATR%.0f",
                     type==ORDER_TYPE_BUY?"BUY":"SELL", session, bADX[1], atr);

   bool result = (type == ORDER_TYPE_BUY)
                 ? trade.Buy(lots,  gSymbol, price, sl, tp, comment)
                 : trade.Sell(lots, gSymbol, price, sl, tp, comment);

   if(result)
   {
      gOpenTicket  = trade.ResultOrder();
      gBEActivated = false;
      gTPReached   = false;           // [FIX #3] reset flag TP
      gTradeTP     = tp;              // guardar TP original
      gTradeSL     = sl;
      gTradesToday++;

      // Contadores por sesión
      if(session == "LON") gLondonTrades++;
      else if(session == "NY") gNYTrades++;

      Print(StringFormat(
         "✅ [v2] %s %s | T:%d | P:%.2f SL:%.2f TP:%.2f | Lots:%.2f | ADX:%.1f | ATR:%.2f",
         type==ORDER_TYPE_BUY?"BUY":"SELL", session,
         gOpenTicket, price, sl, tp, lots, bADX[1], atr));

      if(InpSaveCSV)
         LogTradeOpen(gOpenTicket, type, price, sl, tp, lots, atr);
   }
   else
      Print("❌ Error abriendo: ", trade.ResultRetcodeDescription());
}

//─────────────────────────────────────────────
// CALCULAR LOTAJE
//─────────────────────────────────────────────
double CalculateLots(double slPoints)
{
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = balance * (InpRiskPercent / 100.0);
   double tickValue  = SymbolInfoDouble(gSymbol, SYMBOL_TRADE_TICK_VALUE);
   double tickSize   = SymbolInfoDouble(gSymbol, SYMBOL_TRADE_TICK_SIZE);
   double lotStep    = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_STEP);
   double minLot     = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_MIN);
   double maxLot     = SymbolInfoDouble(gSymbol, SYMBOL_VOLUME_MAX);

   if(tickValue == 0 || tickSize == 0 || slPoints == 0) return minLot;

   double valuePerPoint = tickValue / tickSize;
   double lots = riskAmount / (slPoints * valuePerPoint);
   lots = MathFloor(lots / lotStep) * lotStep;
   return NormalizeDouble(MathMax(minLot, MathMin(maxLot, lots)), 2);
}

//─────────────────────────────────────────────
// GESTIÓN DE TRADE ABIERTO
// FIX #3: Trailing SOLO después de que precio
//         alcanzó el nivel del TP original
//─────────────────────────────────────────────
void ManageOpenTrade()
{
   if(gOpenTicket == 0) return;
   if(!posInfo.SelectByTicket(gOpenTicket)) { gOpenTicket = 0; return; }

   double currentPrice = posInfo.PriceCurrent();
   double openPrice    = posInfo.PriceOpen();
   double currentSL    = posInfo.StopLoss();
   double currentTP    = posInfo.TakeProfit();
   ENUM_POSITION_TYPE posType = posInfo.PositionType();

   if(CopyBuffer(hATR, 0, 0, 2, bATR) < 2) return;
   double atr    = bATR[0];
   double slDist = atr * InpSLMultATR;
   double beDist = slDist * InpBEAtRR;
   int    digits = (int)SymbolInfoInteger(gSymbol, SYMBOL_DIGITS);

   // ── BREAK EVEN ─────────────────────────────────────────────
   if(InpUseBreakEven && !gBEActivated)
   {
      bool beHit = (posType == POSITION_TYPE_BUY  && currentPrice >= openPrice + beDist)
                || (posType == POSITION_TYPE_SELL && currentPrice <= openPrice - beDist);
      if(beHit)
      {
         double newSL = NormalizeDouble(openPrice, digits);
         bool valid   = (posType == POSITION_TYPE_BUY  && newSL > currentSL)
                     || (posType == POSITION_TYPE_SELL && newSL < currentSL);
         if(valid && trade.PositionModify(gOpenTicket, newSL, currentTP))
         {
            gBEActivated = true;
            Print(StringFormat("🔒 [v2] Break Even | T:%d | SL→%.2f", gOpenTicket, newSL));
         }
      }
   }

   // ── FIX #3: TRAILING — solo activo cuando precio tocó TP ──
   if(InpUseTrailing)
   {
      // Verificar si el precio llegó al TP original por primera vez
      if(!gTPReached)
      {
         bool tpTouched = (posType == POSITION_TYPE_BUY  && currentPrice >= gTradeTP)
                       || (posType == POSITION_TYPE_SELL && currentPrice <= gTradeTP);
         if(tpTouched)
         {
            gTPReached = true;
            Print(StringFormat("🎯 [v2] TP alcanzado — activando trailing | T:%d", gOpenTicket));
         }
      }

      // Solo trailing si TP ya fue tocado
      if(gTPReached)
      {
         double trailDist = atr * InpTrailATRMult;
         double newSL     = 0;

         if(posType == POSITION_TYPE_BUY)
         {
            newSL = NormalizeDouble(currentPrice - trailDist, digits);
            if(newSL > currentSL + SymbolInfoDouble(gSymbol, SYMBOL_POINT))
               trade.PositionModify(gOpenTicket, newSL, 0); // TP=0 → sin límite
         }
         else if(posType == POSITION_TYPE_SELL)
         {
            newSL = NormalizeDouble(currentPrice + trailDist, digits);
            if(newSL < currentSL - SymbolInfoDouble(gSymbol, SYMBOL_POINT))
               trade.PositionModify(gOpenTicket, newSL, 0);
         }
      }
   }
}

//─────────────────────────────────────────────
// EVENTO CIERRE DE OPERACIÓN
//─────────────────────────────────────────────
void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest     &request,
                        const MqlTradeResult      &result)
{
   if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;
   ulong dealTicket = trans.deal;
   if(dealTicket == 0) return;
   if(!HistoryDealSelect(dealTicket)) return;
   if(HistoryDealGetInteger(dealTicket, DEAL_ENTRY) != DEAL_ENTRY_OUT) return;
   if(HistoryDealGetInteger(dealTicket, DEAL_MAGIC) != 202602) return;

   double pnl    = HistoryDealGetDouble(dealTicket, DEAL_PROFIT)
                 + HistoryDealGetDouble(dealTicket, DEAL_SWAP)
                 + HistoryDealGetDouble(dealTicket, DEAL_COMMISSION);
   double closeP = HistoryDealGetDouble(dealTicket, DEAL_PRICE);
   string reason = (pnl > 0) ? "WIN" : "LOSS";

   gTotalTrades++;
   if(pnl > 0) { gWinTrades++;  gTotalProfit += pnl; }
   else         { gLossTrades++; gTotalLoss   += MathAbs(pnl); }

   int sz = ArraySize(gProfits);
   ArrayResize(gProfits, sz + 1);
   gProfits[sz] = pnl;

   double equity = AccountInfoDouble(ACCOUNT_EQUITY);
   if(equity > gMaxEquity) gMaxEquity = equity;
   double dd = (gMaxEquity > 0) ? (gMaxEquity - equity) / gMaxEquity * 100.0 : 0;
   if(dd > gMaxDrawdown) gMaxDrawdown = dd;

   // Stats sesión
   string session = GetCurrentSession();
   if(session == "LON" && pnl > 0) gLondonWins++;
   if(session == "NY"  && pnl > 0) gNYWins++;

   gOpenTicket = 0;
   gTPReached  = false;

   Print(StringFormat(
      "📋 [v2] %s | P&L:$%.2f | WR:%.1f%% | PF:%.2f | DD:%.2f%% | ADXblk:%d",
      reason, pnl, WinRate(), ProfitFactor(), gMaxDrawdown, gADXFiltered));

   if(InpSaveCSV) LogTradeClose(dealTicket, closeP, pnl, reason);
}

//─────────────────────────────────────────────
// FIX #1: FILTRO HORARIO CON ZONA MUERTA
//─────────────────────────────────────────────
bool IsValidSession()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int h = dt.hour;

   bool london  = (h >= InpLondonStart && h < InpLondonEnd);   // 08-11h
   bool ny      = (h >= InpNYStart     && h < InpNYEnd);        // 16-19h
   // ZONA MUERTA 13-15h: automáticamente excluida porque
   // LondonEnd=12 y NYStart=16 → gap de 13:00 a 15:59

   return (london || ny);
}

string GetCurrentSession()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   int h = dt.hour;
   if(h >= InpLondonStart && h < InpLondonEnd) return "LON";
   if(h >= InpNYStart     && h < InpNYEnd)     return "NY";
   return "OFF";
}

//─────────────────────────────────────────────
// UTILIDADES
//─────────────────────────────────────────────
int CountOpenTrades()
{
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
      if(posInfo.SelectByIndex(i))
         if(posInfo.Symbol() == gSymbol && posInfo.Magic() == 202602)
            count++;
   return count;
}

void UpdateDailyCounter()
{
   MqlDateTime dt;
   TimeToStruct(TimeCurrent(), dt);
   datetime today = StringToTime(StringFormat("%04d.%02d.%02d 00:00",
                                  dt.year, dt.mon, dt.day));
   if(today != gLastTradeDay)
   {
      gTradesToday  = 0;
      gLastTradeDay = today;
   }
}

double WinRate()
{
   if(gTotalTrades == 0) return 0;
   return NormalizeDouble((double)gWinTrades / gTotalTrades * 100.0, 1);
}

double ProfitFactor()
{
   if(gTotalLoss == 0) return (gTotalProfit > 0) ? 99.0 : 0.0;
   return NormalizeDouble(gTotalProfit / gTotalLoss, 2);
}

double SharpeRatio()
{
   int n = ArraySize(gProfits);
   if(n < 2) return 0;
   double sum = 0;
   for(int i = 0; i < n; i++) sum += gProfits[i];
   double mean = sum / n;
   double variance = 0;
   for(int i = 0; i < n; i++) variance += MathPow(gProfits[i] - mean, 2);
   double stddev = MathSqrt(variance / (n - 1));
   if(stddev == 0) return 0;
   return NormalizeDouble(mean / stddev * MathSqrt(252.0), 2);
}

