// Datos de apertura guardados para el cierre
string gOpenData = "";

void LogTradeOpen(ulong ticket, ENUM_ORDER_TYPE type, double price,
                  double sl, double tp, double lots, double atr)
{
   // Guardamos como string serializado para usar en cierre
   gOpenData = StringFormat("%d|%s|%s|%s|%.2f|%.2f|%.2f|%.2f|%.2f|%.2f",
