   string tp_s      = (n > 6) ? parts[6] : "N/A";
   string lots_s    = (n > 7) ? parts[7] : "N/A";
   string atr_s     = (n > 8) ? parts[8] : "N/A";
   string adx_s     = (n > 9) ? parts[9] : "N/A";

