void LogTradeClose(ulong dealTicket, double closePrice, double pnl, string result)
{
   string fn = InpCSVName + "_Trades.csv";
   int fh = FileOpen(fn, FILE_READ|FILE_WRITE|FILE_CSV|FILE_ANSI, ',');
   if(fh == INVALID_HANDLE) return;
   FileSeek(fh, 0, SEEK_END);

   // Parsear datos de apertura
   string parts[];
   int n = StringSplit(gOpenData, '|', parts);

   string ticket    = (n > 0) ? parts[0] : (string)dealTicket;
   string tipo      = (n > 1) ? parts[1] : "N/A";
   string session   = (n > 2) ? parts[2] : "N/A";
   string openTime  = (n > 3) ? parts[3] : "N/A";
   string openPrice = (n > 4) ? parts[4] : "N/A";
   string sl_s      = (n > 5) ? parts[5] : "N/A";
   string tp_s      = (n > 6) ? parts[6] : "N/A";
   string lots_s    = (n > 7) ? parts[7] : "N/A";
   string atr_s     = (n > 8) ? parts[8] : "N/A";
   string adx_s     = (n > 9) ? parts[9] : "N/A";

   string closeTime = TimeToString((datetime)HistoryDealGetInteger(dealTicket, DEAL_TIME),
                                   TIME_DATE|TIME_MINUTES);

   FileWrite(fh,
      ticket, tipo, session, openTime, openPrice, sl_s, tp_s, lots_s, atr_s, adx_s,
      closeTime, DoubleToString(closePrice, 2),
      DoubleToString(pnl, 2), result,
      gTPReached ? "SI" : "NO",
      DoubleToString(WinRate(), 1),
      DoubleToString(ProfitFactor(), 2),
      DoubleToString(gMaxDrawdown, 2),
      DoubleToString(SharpeRatio(), 2),
      DoubleToString(AccountInfoDouble(ACCOUNT_BALANCE), 2));

   FileClose(fh);
   gOpenData = "";
}

