   // ── [v4-C] TRAILING — arranca desde InpTrailStartR (default 0.5R) ──
   // En v3 el trailing esperaba al TP y nunca se activó (0/402 trades).
   // Ahora arranca cuando el precio avanza 0.5R desde la entrada.
   if(InpUseTrailing)
   {
      bool trailReady = (posType == POSITION_TYPE_BUY  && currentPrice >= openPrice + trailStartDist)
                     || (posType == POSITION_TYPE_SELL && currentPrice <= openPrice - trailStartDist);

      // Detectar y loguear si el TP original fue tocado
      if(!gTPReached)
      {
         bool tpTouched = (posType == POSITION_TYPE_BUY  && currentPrice >= gTradeTP)
                       || (posType == POSITION_TYPE_SELL && currentPrice <= gTradeTP);
         if(tpTouched)
         {
            gTPReached = true;
            Print(StringFormat("🎯 [v4] TP ALCANZADO | T:%d | Precio:%.2f TP:%.2f",
                  gOpenTicket, currentPrice, gTradeTP));
         }
         // Debug: avisar al 70% del camino hacia el TP
         double tpTotal = MathAbs(gTradeTP - openPrice);
         if(tpTotal > 0)
         {
            double tpPct = MathAbs(currentPrice - openPrice) / tpTotal * 100.0;
            if(InpDebugMode && tpPct >= 70.0 && tpPct < 100.0)
               Print(StringFormat("📈 [v4] TP al %.0f%% | P:%.2f → TP:%.2f | T:%d",
                     tpPct, currentPrice, gTradeTP, gOpenTicket));
         }
      }

      if(trailReady)
      {
         double trailDist = atr * InpTrailATRMult;
         double point     = SymbolInfoDouble(gSymbol, SYMBOL_POINT);
         double newSL     = 0;
         // Tras alcanzar TP: quitar límite de TP para dejar correr
         double newTP     = gTPReached ? 0 : currentTP;

         if(posType == POSITION_TYPE_BUY)
         {
            newSL = NormalizeDouble(currentPrice - trailDist, digits);
            if(newSL > currentSL + point)
               trade.PositionModify(gOpenTicket, newSL, newTP);
         }
         else if(posType == POSITION_TYPE_SELL)
         {
            newSL = NormalizeDouble(currentPrice + trailDist, digits);
            if(newSL < currentSL - point)
               trade.PositionModify(gOpenTicket, newSL, newTP);
         }
      }
   }
}

