import {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, PageBreak, LevelFormat,
  TabStopType, TabStopPosition
} from 'docx';
import fs from 'fs';

// ── Colors ──────────────────────────────────────────────
const NAVY    = "1B2A4A";
const GOLD    = "C9A84C";
const LTBLUE  = "D6E8F5";
const LTGRAY  = "F5F5F5";
const MIDGRAY = "DCDCDC";
const GREEN   = "1A6B3A";
const RED_C   = "A02020";
const WHITE   = "FFFFFF";

// ── Helpers ─────────────────────────────────────────────
const br = (sz=120) => new Paragraph({ spacing:{before:sz,after:0}, children:[] });

const hr = () => new Paragraph({
  border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: GOLD, space: 4 } },
  spacing: { before: 80, after: 80 }, children: []
});

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 160 },
    children: [new TextRun({ text, bold: true, size: 36, color: NAVY, font: "Arial" })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 240, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: GOLD, space: 2 } },
    children: [new TextRun({ text, bold: true, size: 28, color: NAVY, font: "Arial" })]
  });
}

function h3(text) {
  return new Paragraph({
    spacing: { before: 180, after: 80 },
    children: [new TextRun({ text, bold: true, size: 24, color: NAVY, font: "Arial" })]
  });
}

function p(text, opts={}) {
  return new Paragraph({
    spacing: { before: 60, after: 80 },
    children: [new TextRun({ text, size: 22, font: "Arial", ...opts })]
  });
}

function bullet(text) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    spacing: { before: 40, after: 40 },
    children: [new TextRun({ text, size: 22, font: "Arial" })]
  });
}

const bdr = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const borders = { top: bdr, bottom: bdr, left: bdr, right: bdr };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function cell(text, opts={}) {
  const { bg=WHITE, bold=false, align=AlignmentType.LEFT, color="000000", sz=20, colSpan } = opts;
  const cellProps = {
    borders,
    shading: { fill: bg, type: ShadingType.CLEAR },
    margins: { top: 80, bottom: 80, left: 140, right: 140 },
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: align,
      children: [new TextRun({ text: String(text), bold, size: sz, font: "Arial", color })]
    })]
  };
  if (colSpan) cellProps.columnSpan = colSpan;
  return new TableCell(cellProps);
}

function headerRow(cols, widths, bg=NAVY) {
  return new TableRow({
    tableHeader: true,
    children: cols.map((c,i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: { fill: bg, type: ShadingType.CLEAR },
      margins: { top: 100, bottom: 100, left: 140, right: 140 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: c, bold: true, size: 20, font: "Arial", color: WHITE })]
      })]
    }))
  });
}

function dataRow(cols, widths, bgs=[]) {
  return new TableRow({
    children: cols.map((c,i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: { fill: bgs[i]||WHITE, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 140, right: 140 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: i===0 ? AlignmentType.LEFT : AlignmentType.CENTER,
        children: [new TextRun({ text: String(c), size: 20, font: "Arial",
          color: typeof c === 'string' && c.startsWith('+') ? GREEN :
                 typeof c === 'string' && c.startsWith('-') ? RED_C : "000000" })]
      })]
    }))
  });
}

// ── BADGE PARAGRAPH ─────────────────────────────────────
function badge(label, value, color=NAVY) {
  return new Paragraph({
    spacing: { before: 40, after: 40 },
    children: [
      new TextRun({ text: `${label}: `, bold: true, size: 22, font: "Arial", color: NAVY }),
      new TextRun({ text: value, size: 22, font: "Arial", color,
        bold: true, highlight: color === GREEN ? "green" : undefined }),
    ]
  });
}

// ────────────────────────────────────────────────────────
// DOCUMENT
// ────────────────────────────────────────────────────────
const doc = new Document({
  numbering: {
    config: [
      { reference: "bullets", levels: [{ level: 0, format: LevelFormat.BULLET, text: "•",
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
    ]
  },
  styles: {
    default: { document: { run: { font: "Arial", size: 22 } } },
    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 36, bold: true, font: "Arial", color: NAVY },
        paragraph: { spacing: { before: 360, after: 160 }, outlineLevel: 0 } },
      { id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 28, bold: true, font: "Arial", color: NAVY },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 1 } },
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 12240, height: 15840 },
        margin: { top: 1080, right: 1260, bottom: 1080, left: 1260 }
      }
    },

    headers: {
      default: new Header({
        children: [
          new Paragraph({
            border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: GOLD, space: 2 } },
            spacing: { before: 0, after: 100 },
            tabStops: [{ type: TabStopType.RIGHT, position: TabStopPosition.MAX }],
            children: [
              new TextRun({ text: "TRIPLE GATE", bold: true, size: 20, font: "Arial", color: NAVY }),
              new TextRun({ text: "\tUS30 | M5 | Automated Trading Strategy", size: 18, font: "Arial", color: "666666" }),
            ]
          })
        ]
      })
    },

    footers: {
      default: new Footer({
        children: [
          new Paragraph({
            border: { top: { style: BorderStyle.SINGLE, size: 4, color: GOLD, space: 2 } },
            spacing: { before: 80, after: 0 },
            tabStops: [{ type: TabStopType.RIGHT, position: TabStopPosition.MAX }],
            alignment: AlignmentType.LEFT,
            children: [
              new TextRun({ text: "Confidential — Internal Use Only", size: 18, font: "Arial", color: "888888" }),
              new TextRun({ text: "\tPage ", size: 18, font: "Arial", color: "888888" }),
              new PageNumber({ type: "current" }),
            ]
          })
        ]
      })
    },

    children: [

      // ════════════════════════════════════════════════
